import { GoogleGenAI } from "@google/genai";

export async function generateTutorialVideo(prompt: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    // Re-instantiate to ensure latest state and key
    const currentAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
    operation = await currentAi.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Failed to generate video");

  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await videoResponse.blob();
  return URL.createObjectURL(blob);
}

import React, { useState } from 'react';
import { Play, Loader2, Video, CheckCircle, AlertCircle, ExternalLink } from 'lucide-react';
import { generateTutorialVideo } from '../services/geminiService';

export const VideoGenerator: React.FC = () => {
  const [isGenerating, setIsGenerating] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loadingStep, setLoadingStep] = useState(0);

  const steps = [
    "Iniciando motor de generación...",
    "Diseñando interfaz de WhatsApp...",
    "Renderizando animaciones de reenvío...",
    "Finalizando tutorial en alta definición...",
    "Procesando descarga..."
  ];

  const handleGenerate = async () => {
    // Check for API Key selection (required for Veo)
    if (typeof window.aistudio !== 'undefined') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
        // Proceeding as per instructions: assume success after trigger
      }
    }

    setIsGenerating(true);
    setError(null);
    setLoadingStep(0);

    const stepInterval = setInterval(() => {
      setLoadingStep(prev => (prev < steps.length - 1 ? prev + 1 : prev));
    }, 15000);

    try {
      const prompt = "A vertical mobile tutorial showing how to forward a WhatsApp message. Step 1: Long press on a message bubble. Step 2: Tap the forward arrow icon at the top right. Step 3: Select a contact from the list. Step 4: Tap the green send button. Modern app interface, clear animations, 3D style.";
      const url = await generateTutorialVideo(prompt);
      setVideoUrl(url);
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("not found")) {
        setError("Error de autenticación. Por favor, selecciona tu clave de API nuevamente.");
        if (typeof window.aistudio !== 'undefined') window.aistudio.openSelectKey();
      } else {
        setError("No se pudo generar el video. Por favor, intenta de nuevo más tarde.");
      }
    } finally {
      clearInterval(stepInterval);
      setIsGenerating(false);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
          <Video className="w-5 h-5 text-amber-600" />
          Generador de Tutoriales IA
        </h2>
        {videoUrl && (
          <button 
            onClick={() => setVideoUrl(null)} 
            className="text-xs text-amber-600 hover:underline font-medium"
          >
            Generar otro
          </button>
        )}
      </div>

      {!videoUrl && !isGenerating && (
        <div className="bg-amber-50 rounded-lg p-4 border border-amber-100">
          <p className="text-sm text-amber-900 mb-4">
            Crea un video tutorial animado que explica paso a paso cómo reenviar mensajes de WhatsApp. 
            Ideal para compartir con clientes que no están familiarizados con la aplicación.
          </p>
          <div className="flex flex-col gap-3">
            <button
              onClick={handleGenerate}
              className="flex items-center justify-center gap-2 bg-amber-700 hover:bg-amber-800 text-white font-bold py-3 px-4 rounded-lg transition-all shadow-md active:scale-95"
            >
              <Play className="w-4 h-4 fill-current" />
              Generar Video Tutorial
            </button>
            <a 
              href="https://ai.google.dev/gemini-api/docs/billing" 
              target="_blank" 
              rel="noopener noreferrer"
              className="text-[10px] text-center text-slate-400 hover:text-slate-600 flex items-center justify-center gap-1"
            >
              Requiere API Key con Facturación habilitada <ExternalLink className="w-2 h-2" />
            </a>
          </div>
        </div>
      )}

      {isGenerating && (
        <div className="flex flex-col items-center justify-center py-12 px-4 text-center space-y-6">
          <div className="relative">
            <div className="w-20 h-20 border-4 border-amber-100 border-t-amber-600 rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center">
              <Video className="w-8 h-8 text-amber-600 animate-pulse" />
            </div>
          </div>
          <div className="space-y-2">
            <p className="text-lg font-bold text-slate-800">{steps[loadingStep]}</p>
            <p className="text-sm text-slate-500 max-w-xs mx-auto">
              La IA está creando tu video desde cero. Esto puede tardar hasta 2 minutos. No cierres esta ventana.
            </p>
          </div>
          <div className="w-full bg-slate-100 rounded-full h-1.5 max-w-xs mx-auto overflow-hidden">
            <div 
              className="bg-amber-600 h-full transition-all duration-1000" 
              style={{ width: `${((loadingStep + 1) / steps.length) * 100}%` }}
            ></div>
          </div>
        </div>
      )}

      {videoUrl && (
        <div className="space-y-4">
          <div className="relative aspect-[9/16] max-w-[280px] mx-auto bg-black rounded-2xl overflow-hidden shadow-2xl border-4 border-slate-900">
            <video 
              src={videoUrl} 
              controls 
              autoPlay 
              loop 
              className="w-full h-full object-cover"
            />
          </div>
          <div className="bg-green-50 border border-green-100 p-3 rounded-lg flex items-start gap-3">
            <CheckCircle className="w-5 h-5 text-green-600 mt-0.5" />
            <p className="text-xs text-green-800">
              <strong>Tutorial Generado:</strong> Puedes descargar este video haciendo clic derecho sobre él y seleccionando "Guardar video como...".
            </p>
          </div>
        </div>
      )}

      {error && (
        <div className="bg-red-50 border border-red-100 p-4 rounded-lg flex items-start gap-3">
          <AlertCircle className="w-5 h-5 text-red-600 mt-0.5" />
          <div className="space-y-1">
