import React, { useState } from 'react';
import { UserPlus, Briefcase, Phone, User, History, Trash2, UserCheck, AlertCircle, Clock, Mail, Send, MessageCircle, Users } from 'lucide-react';
import { ClientData, SellerType, ShippingHistoryItem, SendMethod, GenderType } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  shippingHistory: ShippingHistoryItem[];
  onClearHistory: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  shippingHistory,
  onClearHistory
}) => {
  const [name, setName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('OF');
  const [sendMethod, setSendMethod] = useState<SendMethod>('whatsapp');
  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido. Debe ser +569XXXXXXXX');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!company.trim()) {
      alert('La Empresa / Razón Social es obligatoria.');
      return;
    }

    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod
    };

    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="OF">OF</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Medio de Envío</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => setSendMethod(e.target.value as SendMethod)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">Email</option>
                </select>
              </div>
            </div>
          </div>

          <h2 className="text-lg font-bold text-slate-800 pt-2 flex items-center gap-2 border-t border-slate-100 mt-4">
            <UserPlus className="w-5 h-5 text-amber-700" />
            Datos del Cliente
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Contacto</label>
              <div className="relative">
                <User className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium"
                  placeholder="Ej: Juan (solo Nombre, sin apellido)"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Género</label>
              <div className="relative">
                <Users className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={gender}
                  onChange={(e) => setGender(e.target.value as GenderType)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none text-slate-900 bg-white font-medium"
                >
                  <option value="hombre">Hombre</option>
                  <option value="mujer">Mujer</option>
                </select>
              </div>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Empresa / Razón Social (obligatorio)</label>
            <div className="relative">
              <Briefcase className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
              <input
                type="text"
                value={company}
                onChange={(e) => setCompany(e.target.value)}
                required
                className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium"
                placeholder="Ej: Constructora ABC"
              />
            </div>
          </div>

          {sendMethod === 'whatsapp' ? (
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Teléfono (formato +569xxxxxx)</label>
              <div className="relative">
                <Phone className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="tel"
                  value={phone}
                  onChange={handlePhoneChange}
                  className={`w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium ${
                    phoneError ? 'border-red-500 bg-red-50' : 'border-slate-400'
                  }`}
                  placeholder="Ej: +56912345678"
                  required
                />
              </div>
              {phoneError && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{phoneError}</p>}
            </div>
          ) : (
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Correo Electrónico</label>
              <div className="relative">
                <Mail className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="email"
                  value={email}
                  onChange={handleEmailChange}
                  className={`w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium ${
                    emailError ? 'border-red-500 bg-red-50' : 'border-slate-400'
                  }`}
                  placeholder="Ej: cliente@empresa.com"
                  required
                />
              </div>
              {emailError && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{emailError}</p>}
            </div>
          )}

          <div className="pt-2">
            <button
              type="submit"
              className="w-full bg-amber-700 hover:bg-amber-800 text-white font-bold py-3 rounded-lg transition-all shadow-md active:transform active:scale-95"
            >
              Generar y Guardar
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 overflow-hidden flex flex-col max-h-[400px]">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <History className="w-5 h-5 text-amber-700" />
            Clientes Guardados
          </h2>
          <span className="text-xs font-medium text-slate-400 bg-slate-100 px-2 py-1 rounded-full">
            {savedClients.length}
          </span>
        </div>

        <div className="flex-grow overflow-y-auto space-y-2 -mx-2 px-2 scrollbar-thin scrollbar-thumb-slate-200">
          {savedClients.map((client) => (
            <div 
              key={client.id}
              className={`group flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${
                currentClientId === client.id ? 'bg-amber-50 border-amber-200 shadow-sm' : 'bg-white border-slate-100 hover:border-amber-200 hover:bg-slate-50'
              }`}
              onClick={() => loadClient(client)}
            >
              <div className="flex-grow min-w-0 pr-4">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-bold bg-amber-100 text-amber-800 px-1.5 py-0.5 rounded">{client.seller}</span>
                  <p className="font-semibold text-slate-800 text-sm truncate">{client.company}</p>
                </div>
                <p className="text-xs text-slate-500 truncate flex items-center gap-1 mt-1">
                  {client.sendMethod === 'whatsapp' ? <Phone className="w-3 h-3" /> : <Mail className="w-3 h-3" />}
                  <span className="font-mono text-[10px] bg-slate-100 px-1 rounded">
                    {client.sendMethod === 'whatsapp' ? client.phone : client.email}
                  </span>
                </p>
              </div>
              <button
                onClick={(e) => { e.stopPropagation(); onDeleteClient(client.id); }}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-md transition-all"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 overflow-hidden flex flex-col max-h-[350px]">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <Clock className="w-5 h-5 text-indigo-600" />
            Historial de Envíos
          </h2>
          {shippingHistory.length > 0 && (
            <button onClick={onClearHistory} className="text-xs text-slate-400 hover:text-red-500 transition-colors">Borrar Todo</button>
          )}
        </div>

        <div className="flex-grow overflow-y-auto space-y-2 -mx-2 px-2 scrollbar-thin scrollbar-thumb-slate-200">
          {shippingHistory.map((item) => (
            <div key={item.id} className="p-3 bg-indigo-50/30 border border-indigo-50 rounded-lg flex items-start gap-3">
              <div className="bg-indigo-100 p-1.5 rounded-full mt-0.5">
                {item.method === 'whatsapp' ? <MessageCircle className="w-3 h-3 text-indigo-600" /> : <Mail className="w-3 h-3 text-indigo-600" />}
              </div>
              <div className="flex-grow min-w-0">
                <p className="text-sm font-bold text-slate-800 leading-tight">{item.clientCompany}</p>
                <div className="flex items-center justify-between mt-1">
                  <p className="text-[10px] text-slate-500 truncate">{item.clientName} • {item.method === 'whatsapp' ? item.phone : item.email}</p>
                  <p className="text-[9px] text-slate-400 font-medium whitespace-nowrap ml-2">{item.timestamp}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Info, MessageCircle, ClipboardCheck } from 'lucide-react';
import { ClientData } from '../types';

const DEFAULT_CATALOG_IMAGE = "https://assets.zyrosite.com/AE04NxxDXof684vj/catalogo-infema---acceso-clientes-iwSY3YftcmWoi3OY.jpg";
const OF_EMAIL_GIF = "https://assets.zyrosite.com/AE04NxxDXof684vj/acceso-clientes---catalogo-infema-r8CaKRCd6BfhZdMn.gif";
const NON_OF_EMAIL_IMAGE = "https://assets.zyrosite.com/AE04NxxDXof684vj/catalogo-infema---enlace-webrv-E84pJwYm4kOpHWpI.png";

interface MessagePreviewProps {
  client: ClientData | null;
  onSent: (client: ClientData) => void;
}

export const MessagePreview: React.FC<MessagePreviewProps> = ({ client, onSent }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  useEffect(() => {
    if (client) {
      let salutation = "";
      if (client.name) {
        const prefix = client.gender === 'hombre' ? 'D.' : 'Sra.';
        salutation = `👋 Hola ${prefix} ${client.name},`;
      } else {
        salutation = `${client.company}.\nEstimado cliente,`;
      }

      const footer = "Saludos,\nLorena Barros";
      const divider = "─────────────";

      let cid = "";
      if (client.sendMethod === 'whatsapp') {
        const cleanPhone = client.phone ? client.phone.replace('+569', '') : '00000000';
        cid = cleanPhone.slice(0, -1);
      } else {
        const email = client.email || '';
        const parts = email.split('@');
        cid = parts.length === 2 ? `${parts[0].substring(0, 3)}.${parts[1].substring(0, 3)}`.toLowerCase() : "usr.dom";
      }

      let mainContent = "";
      if (client.seller === 'OF') {
        if (client.sendMethod === 'email') {
          mainContent = `📖 Le comparto el enlace directo al catálogo en línea.\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${footer}`;
        } else {
          mainContent = `📖 Le comparto el enlace directo al catálogo en línea:\n${divider}\n🔗 https://tiendaonline.infema.cl/?v=78.6&cid=${cid}\n${divider}\n📌 Para entrar la primera vez use el Usuario y Contraseña de la foto.\n\n${footer}`;
        }
      } else {
        const sellerPath = client.seller.toLowerCase();
        if (client.sendMethod === 'email') {
          mainContent = `📖 Le comparto el enlace directo al catálogo en línea.\n\n${footer}`;
        } else {
          mainContent = `📖 Le comparto el enlace directo al catálogo en línea:\n${divider}\n🔗 https://catalogo.infema.cl/${sellerPath}?cid=${cid}\n${divider}\n\n${footer}`;
        }
      }
      setEditableMessage(`${salutation}\n\n${mainContent}`);
    }
  }, [client]);

  const handleCopyAndShare = async (method: 'whatsapp' | 'email') => {
    if (!client || !editableMessage) return;

    try {
      let cid = "";
      if (client.sendMethod === 'whatsapp') {
        const cleanPhone = client.phone ? client.phone.replace('+569', '') : '00000000';
        cid = cleanPhone.slice(0, -1);
      } else {
        const email = client.email || '';
        const parts = email.split('@');
        cid = parts.length === 2 ? `${parts[0].substring(0, 3)}.${parts[1].substring(0, 3)}`.toLowerCase() : "usr.dom";
      }

      let clientLink = client.seller === 'OF' ? `https://tiendaonline.infema.cl/?v=78.6&cid=${cid}` : `https://catalogo.infema.cl/${client.seller.toLowerCase()}?cid=${cid}`;
      let imageUrl = client.sendMethod === 'email' ? (client.seller === 'OF' ? OF_EMAIL_GIF : NON_OF_EMAIL_IMAGE) : DEFAULT_CATALOG_IMAGE;

      const parts = editableMessage.split("Saludos,\nLorena Barros");
      const htmlContent = `
        <div style="font-family: Arial, sans-serif; color: #334155; line-height: 1.5;">
          ${(parts[0] || "").replace(/\n/g, '<br>')}
          <br><br>
          <a href="${clientLink}"><img src="${imageUrl}" width="600" style="width: 600px; max-width: 100%; border-radius: 8px;"></a>
          <br><br>
          Saludos,<br>Lorena Barros
        </div>
      `;

      try {
        const data = [new ClipboardItem({
          'text/plain': new Blob([editableMessage], { type: 'text/plain' }),
          'text/html': new Blob([htmlContent], { type: 'text/html' })
        })];
        await navigator.clipboard.write(data);
      } catch (e) {
        await navigator.clipboard.writeText(editableMessage);
      }

      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);
      onSent(client);

      if (method === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        window.open(`mailto:${client.email}?subject=${encodeURIComponent("Catálogo Digital INFEMA")}`, '_blank');
      }
    } catch (err) { console.error(err); }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-48 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm font-medium">Previsualización de Mensaje</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[400px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3">
        <h2 className="font-bold text-slate-700 text-sm flex items-center gap-2">
          <MessageCircle className="w-4 h-4" />
          Vista Previa
        </h2>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden">
        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className="w-full flex-grow bg-[#DCF8C6] p-4 rounded-lg border-none focus:ring-0 text-slate-900 text-base lg:text-lg leading-relaxed font-sans resize-none"
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={() => handleCopyAndShare(client.sendMethod)}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : `Copiar y enviar por ${client.sendMethod}`}
        </button>
      </div>
    </div>
  );
};

export type SellerType = 'MIGUEL' | 'FRANCISCO' | 'HECTOR' | 'MARIA PAZ';
export type SendMethod = 'whatsapp' | 'email';
export type GenderType = 'hombre' | 'mujer';

export interface ClientData {
  id: string;
  name: string;
  company: string;
  phone: string;
  email: string;
  seller: SellerType;
  sendMethod: SendMethod;
  gender: GenderType;
}

export interface ShippingHistoryItem {
  id: string;
  clientName: string;
  clientCompany: string;
  timestamp: string;
  phone?: string;
  email?: string;
  method: SendMethod;
}

import React, { useState } from 'react';
import { UserPlus, Briefcase, Phone, User, History, Trash2, UserCheck, AlertCircle, Clock, Mail, Send, MessageCircle, Users } from 'lucide-react';
import { ClientData, SellerType, ShippingHistoryItem, SendMethod, GenderType } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  shippingHistory: ShippingHistoryItem[];
  onClearHistory: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  shippingHistory,
  onClearHistory
}) => {
  const [name, setName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('MIGUEL');
  const [sendMethod, setSendMethod] = useState<SendMethod>('whatsapp');
  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido. Debe ser +569XXXXXXXX');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!company.trim()) {
      alert('La Empresa / Razón Social es obligatoria.');
      return;
    }

    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod
    };

    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
