export type SellerType = 'OF' | 'MB' | 'FU' | 'HC' | 'MP';
export type SendMethod = 'whatsapp' | 'email';
export type GenderType = 'hombre' | 'mujer';

export interface ClientData {
  id: string;
  name: string;
  company: string;
  phone: string;
  email: string;
  seller: SellerType;
  sendMethod: SendMethod;
  gender: GenderType;
}

export interface ShippingHistoryItem {
  id: string;
  clientName: string;
  clientCompany: string;
  timestamp: string;
  phone?: string;
  email?: string;
  method: SendMethod;
}

import React, { useState } from 'react';
import { UserPlus, Briefcase, Phone, User, History, Trash2, UserCheck, AlertCircle, Clock, Mail, Send, MessageCircle, Users } from 'lucide-react';
import { ClientData, SellerType, ShippingHistoryItem, SendMethod, GenderType } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  shippingHistory: ShippingHistoryItem[];
  onClearHistory: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  shippingHistory,
  onClearHistory
}) => {
  const [name, setName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('OF');
  const [sendMethod, setSendMethod] = useState<sendMethod>('whatsapp');
  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido. Debe ser +569XXXXXXXX');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!company.trim()) {
      alert('La Empresa / Razón Social es obligatoria.');
      return;
    }

    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod
    };

    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="OF">OF</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Medio de Envío</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => setSendMethod(e.target.value as SendMethod)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">Email</option>
                </select>
              </div>
            </div>
          </div>

          <h2 className="text-lg font-bold text-slate-800 pt-2 flex items-center gap-2 border-t border-slate-100 mt-4">
            <UserPlus className="w-5 h-5 text-amber-700" />
            Datos del Cliente
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Contacto</label>
              <div className="relative">
                <User className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium"
                  placeholder="Ej: Juan"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Género</label>
              <div className="relative">
                <Users className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={gender}
                  onChange={(e) => setGender(e.target.value as GenderType)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none text-slate-900 bg-white font-medium"
                >
                  <option value="hombre">Hombre</option>
                  <option value="mujer">Mujer</option>
                </select>
              </div>
