interface MessagePreviewProps {
  client: ClientData | null;
  onSent: (client: ClientData) => void;
}

export const MessagePreview: React.FC<MessagePreviewProps> = ({ client, onSent }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      let salutation = "";
      if (client.name) {
        const prefix = client.gender === 'hombre' ? 'D.' : 'Sra.';
        salutation = `👋 Hola ${prefix} ${client.name},`;
      } else {
        salutation = `${client.company}.\nEstimado cliente,`;
      }

      const divider = "─────────────";

      let cid = "";
      if (client.sendMethod === 'whatsapp') {
        const cleanPhone = client.phone ? client.phone.replace('+569', '') : '00000000';
        cid = cleanPhone.slice(0, -1);
      } else {
        const email = client.email || '';
        const parts = email.split('@');
        cid = parts.length === 2 ? `${parts[0].substring(0, 3)}.${parts[1].substring(0, 3)}`.toLowerCase() : "usr.dom";
      }

      const fullLink = client.seller === 'OF' ? config.link : `${config.link}?cid=${cid}`;
      const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";

      let mainContent = "";
      if (client.seller === 'OF') {
        mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
      } else {
        // MB, FU, HC, MP
        if (client.sendMethod === 'email') {
          mainContent = `${intro}\n${divider}\n🔗 FOTO CON ENLACE\n${divider}\n\n${config.footer}`;
        } else {
          mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n\n${config.footer}`;
        }
      }

      setEditableMessage(`${salutation}\n\n${mainContent}`);
    }
  }, [client]);

  const handleCopyAndShare = async (method: 'whatsapp' | 'email') => {
    if (!client || !editableMessage) return;

    const config = SELLER_CONFIG[client.seller];

    try {
      let cid = "";
      if (client.sendMethod === 'whatsapp') {
        const cleanPhone = client.phone ? client.phone.replace('+569', '') : '00000000';
        cid = cleanPhone.slice(0, -1);
      } else {
        const email = client.email || '';
        const parts = email.split('@');
        cid = parts.length === 2 ? `${parts[0].substring(0, 3)}.${parts[1].substring(0, 3)}`.toLowerCase() : "usr.dom";
      }

      const clientLink = client.seller === 'OF' ? config.link : `${config.link}?cid=${cid}`;
      const imageUrl = config.image;

      const parts = editableMessage.split(config.footer);
      const htmlContent = `
        <div style="font-family: Arial, sans-serif; color: #334155; line-height: 1.5;">
          ${(parts[0] || "").replace(/\n/g, '<br>')}
          <br>
          <a href="${clientLink}"><img src="${imageUrl}" width="600" style="width: 600px; max-width: 100%; border-radius: 8px;"></a>
          <br><br>
          ${config.footer.replace(/\n/g, '<br>')}
        </div>
      `;

      try {
        const data = [new ClipboardItem({
          'text/plain': new Blob([editableMessage], { type: 'text/plain' }),
          'text/html': new Blob([htmlContent], { type: 'text/html' })
        })];
        await navigator.clipboard.write(data);
      } catch (e) {
        await navigator.clipboard.writeText(editableMessage);
      }

      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);
      onSent(client);

      if (method === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        // Abrir el cliente de correo con el asunto específico
        const subject = encodeURIComponent("Adjunto Catálogo Digital");
        const body = encodeURIComponent(editableMessage);
        window.location.href = `mailto:${client.email}?subject=${subject}`;
      }
    } catch (err) { console.error(err); }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-48 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm font-medium">Previsualización de Mensaje</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[400px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3">
        <h2 className="font-bold text-slate-700 text-sm flex items-center gap-2">
          <MessageCircle className="w-4 h-4" />
          Vista Previa
        </h2>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden">
        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className="w-full flex-grow bg-[#DCF8C6] p-4 rounded-lg border-none focus:ring-0 text-slate-900 text-base lg:text-lg leading-relaxed font-sans resize-none"
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={() => handleCopyAndShare(client.sendMethod)}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : `Copiar y enviar por ${client.sendMethod}`}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BookOpen, Share2, CheckCircle2 } from 'lucide-react';
import { ClientManager } from './components/ClientManager';
import { MessagePreview } from './components/MessagePreview';
import { ClientData, ShippingHistoryItem } from './types';

function App() {
  const [currentClient, setCurrentClient] = useState<ClientData | null>(null);
  const [savedClients, setSavedClients] = useState<ClientData[]>([]);
  const [shippingHistory, setShippingHistory] = useState<ShippingHistoryItem[]>([]);

  useEffect(() => {
    const storedClients = localStorage.getItem('infema_v2_clients_vendedores');
    if (storedClients) {
      try { setSavedClients(JSON.parse(storedClients)); } catch (e) { console.error(e); }
    }
    const storedHistory = localStorage.getItem('infema_v2_history_vendedores');
    if (storedHistory) {
      try { setShippingHistory(JSON.parse(storedHistory)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('infema_v2_clients_vendedores', JSON.stringify(savedClients));
  }, [savedClients]);

  useEffect(() => {
    localStorage.setItem('infema_v2_history_vendedores', JSON.stringify(shippingHistory));
  }, [shippingHistory]);

  const handleAddClient = (client: ClientData) => {
    setCurrentClient(client);
    setSavedClients(prev => {
      const existsIdx = prev.findIndex(c => 
        (client.sendMethod === 'whatsapp' ? c.phone === client.phone : c.email === client.email) && 
        c.seller === client.seller
      );
      if (existsIdx !== -1) {
        const updated = [...prev];
        updated[existsIdx] = client;
        return updated;
      }
      return [client, ...prev].slice(0, 100);
    });
  };

  const handleDeleteClient = (idToDelete: string) => {
    setSavedClients(prev => prev.filter(c => c.id !== idToDelete));
    if (currentClient?.id === idToDelete) {
      setCurrentClient(null);
    }
  };

  const handleAddToHistory = (client: ClientData) => {
    const newItem: ShippingHistoryItem = {
      id: Date.now().toString(),
      clientName: client.name || 'Sin nombre',
      clientCompany: client.company || 'Empresa (No Completado)',
      phone: client.sendMethod === 'whatsapp' ? client.phone : undefined,
      email: client.sendMethod === 'email' ? client.email : undefined,
      method: client.sendMethod,
      timestamp: new Date().toLocaleString()
    };
    setShippingHistory(prev => [newItem, ...prev].slice(0, 50));
  };

  const handleClearHistory = () => {
    if (window.confirm('¿Borrar historial de envíos?')) setShippingHistory([]);
  };

  return (
    <div className="flex flex-col min-h-full">
      <header className="bg-[#1e293b] text-white shadow-md sticky top-0 z-50 safe-top flex-shrink-0">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-amber-500/20 p-1 rounded">
              <BookOpen className="w-5 h-5 text-amber-200" />
            </div>
            <h1 className="text-lg font-bold tracking-tight text-amber-50">INFEMA <span className="text-amber-500 font-light">Vendedores</span></h1>
          </div>
          <div className="flex items-center gap-3">
            <div className="text-[10px] font-medium text-slate-400 uppercase tracking-widest">
              Catálogos V2.2
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 py-4 sm:py-6">
        <div className="grid lg:grid-cols-2 gap-4 sm:gap-6">
          <div className="space-y-4">
            <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 shadow-sm">
              <h2 className="text-amber-900 font-bold text-xs uppercase tracking-wider mb-3 flex items-center gap-2">
                <Share2 className="w-4 h-4" />
                Flujo de Trabajo
              </h2>
              <div className="space-y-3">
                <div className="flex items-start gap-2 text-[11px] text-amber-800">
                  <CheckCircle2 className="w-3.5 h-3.5 text-amber-600 mt-0.5 shrink-0" />
                  <span>1- Selecciona el código de Vendedor y el medio de envío.</span>
                </div>
                <div className="flex items-start gap-2 text-[11px] text-amber-800">
                  <CheckCircle2 className="w-3.5 h-3.5 text-amber-600 mt-0.5 shrink-0" />
                  <span>2- Ingresa datos del cliente (Empresa es obligatorio).</span>
                </div>
                <div className="flex items-start gap-2 text-[11px] text-amber-800">
                  <CheckCircle2 className="w-3.5 h-3.5 text-amber-600 mt-0.5 shrink-0" />
                  <div>
                    <span className="font-bold block mb-1">3- Copia y Envía:</span>
                    <ul className="pl-4 space-y-1 list-disc">
                      <li>WhatsApp: Adjunta tu foto manualmente y pega el texto.</li>
                      <li>Email: El link va incrustado en la foto (automático).</li>
                    </ul>
                  </div>
                </div>
              </div>
            </div>

            <ClientManager 
              onClientSelect={handleAddClient} 
              savedClients={savedClients}
              onDeleteClient={handleDeleteClient}
              currentClientId={currentClient?.id}
              shippingHistory={shippingHistory}
              onClearHistory={handleClearHistory}
            />
          </div>

          <div className="h-full">
             <MessagePreview client={currentClient} onSent={handleAddToHistory} />
          </div>
        </div>
      </main>

      <footer className="bg-slate-50 border-t border-slate-200 py-4 mt-auto">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="text-slate-400 text-[10px] font-medium tracking-wide uppercase">INFEMA • EQUIPO DE VENTAS • {new Date().getFullYear()}</p>
        </div>
      </footer>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { UserPlus, Briefcase, Phone, User, History, Trash2, UserCheck, AlertCircle, Clock, Mail, Send, MessageCircle, Users } from 'lucide-react';
import { ClientData, SellerType, ShippingHistoryItem, SendMethod, GenderType } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  shippingHistory: ShippingHistoryItem[];
  onClearHistory: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  shippingHistory,
  onClearHistory
}) => {
  const [name, setName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('OF');
  // Fixed: Use the 'SendMethod' type instead of the 'sendMethod' variable name in the generic argument.
  const [sendMethod, setSendMethod] = useState<SendMethod>('whatsapp');
  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido. Debe ser +569XXXXXXXX');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!company.trim()) {
      alert('La Empresa / Razón Social es obligatoria.');
      return;
    }

    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod
    };

    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={seller}
