interface MessagePreviewProps {
  client: ClientData | null;
}

export const MessagePreview: React.FC<MessagePreviewProps> = ({ client }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  // Función actualizada para generar el CID
  const generateCID = (client: ClientData) => {
    if (client.sendMethod === 'whatsapp') {
      // Eliminar +569 inicial y el último dígito
      const cleanPhone = client.phone.replace('+569', '');
      return cleanPhone.slice(0, -1);
    } else {
      // Email: 3 primeros antes del @ + "." + 3 primeros después del @
      const email = client.email || '';
      const parts = email.split('@');
      if (parts.length === 2) {
        const pre = parts[0].substring(0, 3);
        const post = parts[1].substring(0, 3);
        return `${pre}.${post}`.toLowerCase();
      }
      return "usr.dom";
    }
  };

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      const cid = generateCID(client);

      let salutation = "";
      if (client.name) {
        const nameParts = client.name.trim().split(/\s+/);
        let shortName = "";

        // Lógica de saludo: 
        // 1 o 2 palabras -> Usar solo la primera (Ej: Juan Pérez -> Juan)
        // 3 o más palabras -> Usar las dos primeras (Ej: Ana María Pérez -> Ana María)
        if (nameParts.length <= 2) {
          shortName = nameParts[0];
        } else {
          shortName = nameParts.slice(0, 2).join(" ");
        }

        const prefix = client.gender === 'hombre' ? 'D.' : 'Sra.';
        salutation = `👋 Hola ${prefix} ${shortName},`;
      } else {
        salutation = `${client.company}.\nEstimado cliente,`;
      }

      const divider = "─────────────";

      // Construir el enlace con el CID para todos los vendedores
      const connector = config.link.includes('?') ? '&' : '?';
      const fullLink = `${config.link}${connector}cid=${cid}`;

      let mainContent = "";
      if (client.sendMethod === 'email') {
        const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando).";
        // MODO EMAIL: Sin líneas divisoras, espaciado limpio

        if (client.seller === 'OF') {
          // OF: Instrucciones antes del footer
          mainContent = `${intro}\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
        } else {
          // Otros: Intro y footer
          mainContent = `${intro}\n\n${config.footer}`;
        }
      } else {
        const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";
        // MODO WHATSAPP: Con divisores y enlace explícito
        if (client.seller === 'OF') {
          mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
        } else {
          mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n\n${config.footer}`;
        }
      }

      setEditableMessage(`${salutation}\n\n${mainContent}`);
    }
  }, [client]);

  const handleCopyAndShare = async (method: 'whatsapp' | 'email') => {
    if (!client || !editableMessage) return;

    const config = SELLER_CONFIG[client.seller];
    const cid = generateCID(client);
    const connector = config.link.includes('?') ? '&' : '?';
    const clientLink = `${config.link}${connector}cid=${cid}`;
    const imageUrl = config.image;

    try {
      let htmlContent = "";

      if (client.sendMethod === 'email') {
        // Construcción HTML específica para Email (Outlook Escritorio)

        // Reemplazamos los saltos de línea por <br>
        let bodyHtml = editableMessage.replace(/\n/g, '<br>');

        // Imagen HTML sin <br> externos para reducir espacio, margen controlado en el div
        const imageHtml = `
          <div style="margin: 10px 0 10px 0;">
            <a href="${clientLink}" target="_blank">
              <img src="${imageUrl}" width="600" alt="Catálogo Infema" style="width: 600px; max-width: 100%; height: auto; border: 0; display: block; border-radius: 8px;">
            </a>
          </div>
        `;

        // Buscamos el footer para insertar la imagen justo antes
        const footerHtml = config.footer.replace(/\n/g, '<br>');
        if (bodyHtml.includes(footerHtml)) {
          const parts = bodyHtml.split(footerHtml);
          // Insertamos la imagen antes del footer
          bodyHtml = `${parts[0]}${imageHtml}${footerHtml}${parts[1] || ''}`;
        } else {
          // Fallback por si se editó drásticamente el mensaje
          bodyHtml = `${bodyHtml}${imageHtml}`;
        }

        htmlContent = `
          <div style="font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; color: #334155; line-height: 1.6; font-size: 11pt;">
            ${bodyHtml}
          </div>
        `;
      } else {
        // Construcción HTML para WhatsApp
        const parts = editableMessage.split(config.footer);
        htmlContent = `
          <div style="font-family: sans-serif;">
            ${(parts[0] || "").replace(/\n/g, '<br>')}
            <br>
            <a href="${clientLink}"><img src="${imageUrl}" width="400"></a>
            <br>
            ${config.footer.replace(/\n/g, '<br>')}
          </div>
        `;
      }

      // Intentar copiar tanto texto plano como HTML
      try {
        const data = [new ClipboardItem({
          'text/plain': new Blob([editableMessage], { type: 'text/plain' }),
          'text/html': new Blob([htmlContent], { type: 'text/html' })
        })];
        await navigator.clipboard.write(data);
      } catch (e) {
        await navigator.clipboard.writeText(editableMessage);
      }

      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);

      if (method === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        // Abrir cliente de correo por defecto
        const subject = encodeURIComponent("Adjunto Catálogo Digital");
        window.location.href = `mailto:${client.email}?subject=${subject}`;
      }
    } catch (err) {
      console.error('Error al copiar/compartir:', err);
    }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-48 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm font-medium">Previsualización de Mensaje</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[400px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3 flex items-center justify-between">
        <h2 className="font-bold text-slate-700 text-sm flex items-center gap-2">
          <MessageCircle className="w-4 h-4" />
          Vista Previa {client.sendMethod === 'email' ? '(Email)' : '(WhatsApp)'}
        </h2>
        {client.sendMethod === 'email' && (
          <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-bold uppercase tracking-tight">Vínculo en Imagen</span>
        )}
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden">
        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className={`w-full flex-grow p-4 rounded-lg border-none focus:ring-0 text-slate-900 text-base lg:text-lg leading-relaxed font-sans resize-none transition-colors ${
            client.sendMethod === 'whatsapp' ? 'bg-[#DCF8C6]' : 'bg-indigo-50/50'
          }`}
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={() => handleCopyAndShare(client.sendMethod)}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : (client.sendMethod === 'email' ? 'Copiar Abrir Correo' : 'Copiar y abrir WhatsApp')}
        </button>
        <p className="text-[10px] text-slate-400 text-center mt-2 font-medium">
          {client.sendMethod === 'email' 
            ? 'Se copiará el mensaje con la foto vinculada. Pégalo en tu correo.' 
            : 'Se copiará el texto para WhatsApp. Recuerda adjuntar la foto manualmente.'}
        </p>
      </div>
    </div>
  );
};

