  savedClients, 
  onDeleteClient,
  currentClientId,
  onExportClients
}) => {
  const [name, setName] = useState('');
  const [lastName, setLastName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('OF');
  const [sendMethod, setSendMethod] = useState<SendMethod>('whatsapp');
  const [deliveryFormat, setDeliveryFormat] = useState<DeliveryFormat>('link');
  const [pdfFiles, setPdfFiles] = useState<File[]>([]);

  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido. Debe ser +569XXXXXXXX');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files);
      const updatedFiles = [...pdfFiles, ...newFiles].slice(0, 15);
      setPdfFiles(updatedFiles);
    }
  };

  const removeFile = (index: number) => {
    setPdfFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!company.trim()) {
      alert('La Empresa / Razón Social es obligatoria.');
      return;
    }

    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      lastName: lastName.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod,
      deliveryFormat,
      attachedFiles: pdfFiles.map(f => f.name)
    };

    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setLastName(client.lastName || '');
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
    setDeliveryFormat(client.deliveryFormat || 'link');
    setPdfFiles([]); // Los archivos reales no se pueden recuperar del string guardado
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 mb-2">
             <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Formato de Envío</label>
             <div className="relative">
                <FileText className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={deliveryFormat}
                  onChange={(e) => setDeliveryFormat(e.target.value as DeliveryFormat)}
                  className="w-full pl-10 pr-4 py-2 bg-white border border-slate-300 text-slate-900 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all font-bold appearance-none"
                >
                  <option value="link">Enlace a catálogo en línea</option>
                  <option value="pdf">PDFs adjuntos</option>
                </select>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="OF">OF</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Medio de Envío</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => setSendMethod(e.target.value as SendMethod)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">Email</option>
                </select>
              </div>
            </div>
          </div>

          <h2 className="text-lg font-bold text-slate-800 pt-2 flex items-center gap-2 border-t border-slate-100 mt-4">
            <UserPlus className="w-5 h-5 text-amber-700" />
            Datos del Cliente
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nombre</label>
              <div className="relative">
                <User className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium"
                  placeholder="Ej: Juan"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Apellido</label>
              <div className="relative">
                <User className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium"
                  placeholder="Ej: Pérez"
                />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Empresa / Razón Social (obligatorio)</label>
              <div className="relative">
                <Briefcase className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={company}
                  onChange={(e) => setCompany(e.target.value)}
                  required
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all text-slate-900 bg-white font-medium"
                  placeholder="Ej: Constructora ABC"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Género Saludo</label>
              <div className="relative">
                <Users className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={gender}
                  onChange={(e) => setGender(e.target.value as GenderType)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none text-slate-900 bg-white font-medium"
                >
                  <option value="hombre">Hombre (D.)</option>
                  <option value="mujer">Mujer (Sra.)</option>
                </select>
              </div>
            </div>

            <div>
              {sendMethod === 'whatsapp' ? (
                <>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Teléfono (+569...)</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                    <input
                      type="tel"
                      value={phone}
                      onChange={handlePhoneChange}
                      className={`w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all text-slate-900 bg-white font-medium ${
                        phoneError ? 'border-red-500 bg-red-50' : 'border-slate-400'
                      }`}
                      placeholder="+56912345678"
                      required
                    />
                  </div>
                  {phoneError && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{phoneError}</p>}
                </>
              ) : (
                <>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Correo Electrónico</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                    <input
                      type="email"
                      value={email}
                      onChange={handleEmailChange}
                      className={`w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all text-slate-900 bg-white font-medium ${
                        emailError ? 'border-red-500 bg-red-50' : 'border-slate-400'
                      }`}
                      placeholder="cliente@empresa.com"
                      required
                    />
                  </div>
                  {emailError && <p className="mt-1 text-xs text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3" />{emailError}</p>}
                </>
              )}
            </div>
          </div>

          {deliveryFormat === 'pdf' && (
            <div className="bg-amber-50 p-4 rounded-lg border border-amber-200 mt-4">
              <label className="block text-sm font-bold text-amber-900 mb-2 flex items-center gap-2">
                <Upload className="w-4 h-4" />
                Cargar Catálogos PDF (Máx. 15)
              </label>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                accept=".pdf"
                multiple
                className="hidden"
              />
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-2 px-4 bg-white border-2 border-dashed border-amber-300 rounded-lg text-amber-700 font-bold hover:bg-amber-100 transition-colors flex items-center justify-center gap-2"
              >
                <Upload className="w-4 h-4" />
                Seleccionar archivos
              </button>

              {pdfFiles.length > 0 && (
                <div className="mt-3 space-y-1">
                  {pdfFiles.map((file, index) => (
                    <div key={index} className="flex items-center justify-between bg-white p-2 rounded border border-amber-100 text-xs text-slate-600">
                      <span className="truncate flex-grow font-medium">{file.name}</span>
                      <button 
                        type="button"
                        onClick={() => removeFile(index)}
                        className="ml-2 text-red-400 hover:text-red-600"
                      >
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  ))}
                  <p className="text-[10px] text-amber-600 mt-2 font-bold uppercase">{pdfFiles.length} de 15 archivos cargados</p>
                </div>
              )}
            </div>
          )}

          <div className="pt-2">
            <button
              type="submit"
              className="w-full bg-amber-700 hover:bg-amber-800 text-white font-bold py-3 rounded-lg transition-all shadow-md active:transform active:scale-95"
            >
              Generar y Guardar
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 overflow-hidden flex flex-col max-h-[500px]">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <History className="w-5 h-5 text-amber-700" />
            Clientes Guardados
          </h2>
          <div className="flex items-center gap-2">
             <span className="text-xs font-medium text-slate-400 bg-slate-100 px-2 py-1 rounded-full">
              {savedClients.length}
            </span>
            {savedClients.length > 0 && (
              <button
                onClick={onExportClients}
                className="flex items-center gap-1 text-[10px] font-bold bg-green-100 text-green-700 px-2 py-1 rounded hover:bg-green-200 transition-colors"
                title="Descargar lista en Excel (.csv)"
              >
                <Download className="w-3 h-3" />
                Excel
              </button>
            )}
          </div>
        </div>

        <div className="flex-grow overflow-y-auto space-y-2 -mx-2 px-2 scrollbar-thin scrollbar-thumb-slate-200">
          {savedClients.map((client) => (
            <div 
              key={client.id}
              className={`group flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${
                currentClientId === client.id ? 'bg-amber-50 border-amber-200 shadow-sm' : 'bg-white border-slate-100 hover:border-amber-200 hover:bg-slate-50'
              }`}
              onClick={() => loadClient(client)}
            >
              <div className="flex-grow min-w-0 pr-4">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-bold bg-amber-100 text-amber-800 px-1.5 py-0.5 rounded">{client.seller}</span>
                  <p className="font-semibold text-slate-800 text-sm truncate">{client.company}</p>
                </div>
                <div className="flex items-center gap-2 mt-1">
                   <p className="text-xs text-slate-500 truncate flex items-center gap-1">
                    {client.sendMethod === 'whatsapp' ? <Phone className="w-3 h-3" /> : <Mail className="w-3 h-3" />}
                    <span className="font-mono text-[10px] bg-slate-100 px-1 rounded">
                      {client.sendMethod === 'whatsapp' ? client.phone : client.email}
                    </span>
                  </p>
                  <span className="text-[9px] font-bold text-amber-600 bg-amber-50 px-1 rounded border border-amber-100 uppercase">{client.deliveryFormat}</span>
                </div>
              </div>
              <button
                onClick={(e) => { e.stopPropagation(); onDeleteClient(client.id); }}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-md transition-all"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

