interface MessagePreviewProps {
  client: ClientData | null;
}

export const MessagePreview: React.FC<MessagePreviewProps> = ({ client }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  // Función para generar el CID único según el medio
  const generateCID = (client: ClientData) => {
    if (client.sendMethod === 'whatsapp') {
      const cleanPhone = client.phone.replace('+569', '');
      return cleanPhone.slice(0, -1);
    } else {
      const email = client.email || '';
      const parts = email.split('@');
      if (parts.length === 2) {
        const pre = parts[0].substring(0, 3);
        const post = parts[1].substring(0, 3);
        return `${pre}.${post}`.toLowerCase();
      }
      return "usr.dom";
    }
  };

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      const cid = generateCID(client);

      let salutation = "";
      if (client.name) {
        const prefix = client.gender === 'hombre' ? 'D.' : 'Sra.';
        salutation = `👋 Hola ${prefix} ${client.name},`;
      } else {
        salutation = `${client.company}.\nEstimado cliente,`;
      }

      const divider = "─────────────";
      const connector = config.link.includes('?') ? '&' : '?';
      const fullLink = `${config.link}${connector}cid=${cid}`;

      let mainContent = "";

      if (client.deliveryFormat === 'pdf') {
        // MODO PDF: Incluye marcador para la firma si es Email
        const signatureMarker = client.sendMethod === 'email' ? "\n\n[ FIRMA PROFESIONAL ]" : "";
        mainContent = `Adjunto catálogos en PDF.${signatureMarker}\n\n${config.footer}`;
      } else {
        // MODO ENLACE
        if (client.sendMethod === 'email') {
          const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando).";
          if (client.seller === 'OF') {
            mainContent = `${intro}\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
          } else {
            mainContent = `${intro}\n\n${config.footer}`;
          }
        } else {
          const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";
          if (client.seller === 'OF') {
            mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
          } else {
            mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n\n${config.footer}`;
          }
        }
      }

      // Eliminado el salto de línea extra (\n\n cambió a \n)
      setEditableMessage(`${salutation}\n${mainContent}`);
    }
  }, [client]);

  const handleCopyAndShare = async (method: 'whatsapp' | 'email') => {
    if (!client || !editableMessage) return;

    const config = SELLER_CONFIG[client.seller];
    const cid = generateCID(client);
    const connector = config.link.includes('?') ? '&' : '?';
    const clientLink = `${config.link}${connector}cid=${cid}`;
    const imageUrl = config.image;

    try {
      let htmlContent = "";

      if (client.sendMethod === 'email') {
        let bodyHtml = editableMessage.replace(/\n/g, '<br>');

        if (client.deliveryFormat === 'pdf') {
          bodyHtml = bodyHtml.replace('[ FIRMA PROFESIONAL ]', SIGNATURE_HTML);
        } else {
          const footerHtml = config.footer.replace(/\n/g, '<br>');
          const visualBlock = `
            <div style="margin: 15px 0;">
              <a href="${clientLink}" target="_blank">
                <img src="${imageUrl}" width="600" alt="Catálogo Infema" style="width: 600px; max-width: 100%; height: auto; border: 0; display: block; border-radius: 8px;">
              </a>
            </div>
          `;
          if (bodyHtml.includes(footerHtml)) {
            const parts = bodyHtml.split(footerHtml);
            bodyHtml = `${parts[0]}${visualBlock}${footerHtml}${parts[1] || ''}`;
          } else {
            bodyHtml = `${bodyHtml}${visualBlock}`;
          }
        }

        htmlContent = `
          <div style="font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; color: #334155; line-height: 1.6; font-size: 11pt;">
            ${bodyHtml}
          </div>
        `;
      } else {
        const parts = editableMessage.split(config.footer);
        const textBefore = (parts[0] || "").replace(/\n/g, '<br>');
        const textAfter = config.footer.replace(/\n/g, '<br>');

        if (client.deliveryFormat === 'pdf') {
          htmlContent = `<div style="font-family: sans-serif;">${textBefore}${textAfter}</div>`;
        } else {
          htmlContent = `
            <div style="font-family: sans-serif;">
              ${textBefore}
              <br>
              <a href="${clientLink}"><img src="${imageUrl}" width="400"></a>
              <br>
              ${textAfter}
            </div>
          `;
        }
      }

      const plainText = editableMessage.replace('[ FIRMA PROFESIONAL ]', '');

      try {
        const data = [new ClipboardItem({
          'text/plain': new Blob([plainText], { type: 'text/plain' }),
          'text/html': new Blob([htmlContent], { type: 'text/html' })
        })];
        await navigator.clipboard.write(data);
      } catch (e) {
        await navigator.clipboard.writeText(plainText);
      }

      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);

      if (method === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        const subject = encodeURIComponent(client.deliveryFormat === 'pdf' ? "Adjunto Catálogos PDF" : "Adjunto Catálogo Digital");
        window.location.href = `mailto:${client.email}?subject=${subject}`;
      }
    } catch (err) {
      console.error('Error al compartir:', err);
    }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-48 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm font-medium">Previsualización de Mensaje</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[400px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3 flex items-center justify-between">
        <h2 className="font-bold text-slate-700 text-sm flex items-center gap-2">
          <MessageCircle className="w-4 h-4" />
          Vista Previa {client.sendMethod === 'email' ? '(Email)' : '(WhatsApp)'}
          <span className="text-[10px] bg-amber-100 text-amber-700 px-2 py-0.5 rounded ml-2 uppercase font-bold tracking-tight">
            {client.deliveryFormat === 'pdf' ? 'PDFs Adjuntos' : 'Enlace Web'}
          </span>
        </h2>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden">
        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className={`w-full flex-grow p-4 rounded-lg border-none focus:ring-0 text-slate-900 text-base lg:text-lg leading-relaxed font-sans resize-none transition-colors ${
            client.sendMethod === 'whatsapp' ? 'bg-[#DCF8C6]' : 'bg-indigo-50/50'
          }`}
          spellCheck="false"
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={() => handleCopyAndShare(client.sendMethod)}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : (client.sendMethod === 'email' ? 'Copiar Abrir Correo' : 'Copiar y abrir WhatsApp')}
        </button>
        <p className="text-[10px] text-slate-400 text-center mt-2 font-medium">
          {client.deliveryFormat === 'pdf' && client.sendMethod === 'email'
            ? 'Copiando texto + Firma Wisestamp. Adjunta los PDFs manualmente.' 
            : (client.sendMethod === 'email' 
                ? 'Copiando texto + Foto vinculada. Pégalo en tu correo.' 
                : 'Copiando texto para WhatsApp. Adjunta la foto manualmente.')}
        </p>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { UserPlus, Briefcase, Phone, User, History, Trash2, UserCheck, AlertCircle, Mail, Send, Users, Download, FileText, Upload, X } from 'lucide-react';
import { ClientData, SellerType, SendMethod, GenderType, DeliveryFormat } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  onExportClients: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  onExportClients
}) => {
  const [name, setName] = useState('');
  const [lastName, setLastName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('OF');
  const [sendMethod, setSendMethod] = useState<SendMethod>('whatsapp');
  const [deliveryFormat, setDeliveryFormat] = useState<DeliveryFormat>('link');
  const [pdfFiles, setPdfFiles] = useState<File[]>([]);

  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido. Debe ser +569XXXXXXXX');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files);
      const updatedFiles = [...pdfFiles, ...newFiles].slice(0, 15);
      setPdfFiles(updatedFiles);
    }
  };

  const removeFile = (index: number) => {
    setPdfFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!company.trim()) {
      alert('La Empresa / Razón Social es obligatoria.');
      return;
    }

    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      lastName: lastName.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod,
      deliveryFormat,
      attachedFiles: pdfFiles.map(f => f.name)
    };

    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setLastName(client.lastName || '');
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
    setDeliveryFormat(client.deliveryFormat || 'link');
    setPdfFiles([]); 
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="bg-slate-50 p-4 rounded-lg border border-slate-100 mb-2">
             <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">Formato de Envío</label>
             <div className="relative">
                <FileText className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={deliveryFormat}
                  onChange={(e) => setDeliveryFormat(e.target.value as DeliveryFormat)}
                  className="w-full pl-10 pr-4 py-2 bg-white border border-slate-300 text-slate-900 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all font-bold appearance-none"
                >
                  <option value="link">Enlace a catálogo en línea</option>
                  <option value="pdf">PDFs adjuntos</option>
                </select>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="OF">OF</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Medio de Envío</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => setSendMethod(e.target.value as SendMethod)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">Email</option>
                </select>
              </div>
            </div>
          </div>

          <h2 className="text-lg font-bold text-slate-800 pt-2 flex items-center gap-2 border-t border-slate-100 mt-4">
            <UserPlus className="w-5 h-5 text-amber-700" />
            Datos del Cliente
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Género</label>
              <div className="relative">
                <Users className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={gender}
                  onChange={(e) => setGender(e.target.value as GenderType)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 outline-none transition-all appearance-none text-slate-900 bg-white font-medium"
                >
                  <option value="hombre">Hombre (D.)</option>
                  <option value="mujer">Mujer (Sra.)</option>
