              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                accept=".pdf"
                multiple
                className="hidden"
              />
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-2 px-4 bg-white border-2 border-dashed border-amber-300 rounded-lg text-amber-700 font-bold hover:bg-amber-100 transition-colors flex items-center justify-center gap-2"
              >
                <Upload className="w-4 h-4" />
                Seleccionar archivos
              </button>

              {pdfFiles.length > 0 && (
                <div className="mt-3 space-y-1">
                  {pdfFiles.map((file, index) => (
                    <div key={index} className="flex items-center justify-between bg-white p-2 rounded border border-amber-100 text-xs text-slate-600">
                      <span className="truncate flex-grow font-medium">{file.name}</span>
                      <button 
                        type="button"
                        onClick={() => removeFile(index)}
                        className="ml-2 text-red-400 hover:text-red-600"
                      >
                        <X className="w-4 h-4" />
                      </button>
                    </div>
                  ))}
                  <p className="text-[10px] text-amber-600 mt-2 font-bold uppercase">{pdfFiles.length} de 15 archivos cargados</p>
                </div>
              )}
            </div>
          )}

          <div className="pt-2">
            <button
              type="submit"
              className="w-full bg-amber-700 hover:bg-amber-800 text-white font-bold py-3 rounded-lg transition-all shadow-md active:transform active:scale-95"
            >
              Generar y Guardar
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 overflow-hidden flex flex-col max-h-[500px]">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <History className="w-5 h-5 text-amber-700" />
            Clientes Guardados
          </h2>
          <div className="flex items-center gap-2">
             <span className="text-xs font-medium text-slate-400 bg-slate-100 px-2 py-1 rounded-full">
              {savedClients.length}
            </span>
            {savedClients.length > 0 && (
              <button
                onClick={onExportClients}
                className="flex items-center gap-1 text-[10px] font-bold bg-green-100 text-green-700 px-2 py-1 rounded hover:bg-green-200 transition-colors"
                title="Descargar lista en Excel (.csv)"
              >
                <Download className="w-3 h-3" />
                Excel
              </button>
            )}
          </div>
        </div>

        <div className="flex-grow overflow-y-auto space-y-2 -mx-2 px-2 scrollbar-thin scrollbar-thumb-slate-200">
          {savedClients.map((client) => (
            <div 
              key={client.id}
              className={`group flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${
                currentClientId === client.id ? 'bg-amber-50 border-amber-200 shadow-sm' : 'bg-white border-slate-100 hover:border-amber-200 hover:bg-slate-50'
              }`}
              onClick={() => loadClient(client)}
            >
              <div className="flex-grow min-w-0 pr-4">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-bold bg-amber-100 text-amber-800 px-1.5 py-0.5 rounded">{client.seller}</span>
                  <p className="font-semibold text-slate-800 text-sm truncate">{client.company}</p>
                </div>
                <div className="flex items-center gap-2 mt-1">
                   <p className="text-xs text-slate-500 truncate flex items-center gap-1">
                    {client.sendMethod === 'whatsapp' ? <Phone className="w-3 h-3" /> : <Mail className="w-3 h-3" />}
                    <span className="font-mono text-[10px] bg-slate-100 px-1 rounded">
                      {client.sendMethod === 'whatsapp' ? client.phone : client.email}
                    </span>
                  </p>
                  <span className="text-[9px] font-bold text-amber-600 bg-amber-50 px-1 rounded border border-amber-100 uppercase">{client.deliveryFormat}</span>
                </div>
              </div>
              <button
                onClick={(e) => { e.stopPropagation(); onDeleteClient(client.id); }}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-md transition-all"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Info, MessageCircle, ClipboardCheck } from 'lucide-react';
import { ClientData, SellerType } from '../types';

const SELLER_CONFIG: Record<SellerType, { image: string; link: string; footer: string }> = {
  OF: {
    image: "https://assets.zyrosite.com/AE04NxxDXof684vj/acceso-clientes---catalogo-infema-r8CaKRCd6BfhZdMn.gif",
    link: "https://tiendaonline.infema.cl/?v=92.6",
