              </button>

              {pdfFiles.length > 0 && (
                <div className="mt-3 space-y-1">
                  {pdfFiles.map((file, index) => (
                    <div key={index} className="flex items-center justify-between bg-white p-2 rounded border border-amber-100 text-xs text-slate-600">
                      <span className="truncate flex-grow font-medium">{file.name}</span>
                      <button 
                        type="button"
                        onClick={() => removeFile(index)}
                        className="ml-2 text-red-400 hover:text-red-600"
