export const MessagePreview: React.FC<MessagePreviewProps> = ({ client }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  const generateCID = (client: ClientData) => {
    if (client.sendMethod === 'whatsapp') {
      const cleanPhone = client.phone.replace('+569', '');
      return cleanPhone.slice(0, -1);
    } else {
      const email = client.email || '';
      const parts = email.split('@');
      if (parts.length === 2) {
        const pre = parts[0].substring(0, 3);
        const post = parts[1].substring(0, 3);
        return `${pre}.${post}`.toLowerCase();
      }
      return "usr.dom";
    }
  };

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      const cid = generateCID(client);

      let salutation = "";
      if (client.name) {
        const prefix = client.gender === 'hombre' ? 'D.' : 'Sra.';
        salutation = `👋 Hola ${prefix} ${client.name},`;
      } else {
        salutation = `${client.company}.\nEstimado cliente,`;
      }

      const divider = "─────────────";
      const connector = config.link.includes('?') ? '&' : '?';
      const fullLink = `${config.link}${connector}cid=${cid}`;

      let mainContent = "";

      if (client.deliveryFormat === 'pdf') {
        // MODO PDF: Firma antes del cierre
        const signatureMarker = client.sendMethod === 'email' ? "[ FIRMA PROFESIONAL ]\n\n" : "";
        mainContent = `Adjunto catálogos en PDF.\n\n${signatureMarker}${config.footer}`;
      } else {
        // MODO ENLACE
        if (client.sendMethod === 'email') {
          const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando).";
          if (client.seller === 'OF') {
            mainContent = `${intro}\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
          } else {
            mainContent = `${intro}\n\n${config.footer}`;
          }
        } else {
          const intro = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";
          if (client.seller === 'OF') {
            mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`;
          } else {
            mainContent = `${intro}\n${divider}\n🔗 ${fullLink}\n${divider}\n\n${config.footer}`;
          }
        }
      }

      // ESPACIADO: Eliminado el doble salto tras el saludo (\n en lugar de \n\n)
      setEditableMessage(`${salutation}\n${mainContent}`);
    }
  }, [client]);

  const handleCopyAndShare = async (method: 'whatsapp' | 'email') => {
    if (!client || !editableMessage) return;

    const config = SELLER_CONFIG[client.seller];
    const cid = generateCID(client);
    const connector = config.link.includes('?') ? '&' : '?';
    const clientLink = `${config.link}${connector}cid=${cid}`;
    const imageUrl = config.image;

    try {
      let htmlContent = "";

      if (client.sendMethod === 'email') {
        let bodyHtml = editableMessage.replace(/\n/g, '<br>');

        if (client.deliveryFormat === 'pdf') {
          // Reemplazo en el HTML para que la firma quede antes del footer
          bodyHtml = bodyHtml.replace('[ FIRMA PROFESIONAL ]', SIGNATURE_HTML);
        } else {
          // Para LINK: Imagen antes del footer
          const footerHtml = config.footer.replace(/\n/g, '<br>');
          const visualBlock = `
            <div style="margin: 20px 0;">
              <a href="${clientLink}" target="_blank">
                <img src="${imageUrl}" width="600" alt="Catálogo Infema" style="width: 600px; max-width: 100%; height: auto; border: 0; display: block; border-radius: 8px;">
              </a>
            </div>
          `;

          if (bodyHtml.includes(footerHtml)) {
             bodyHtml = bodyHtml.replace(footerHtml, visualBlock + footerHtml);
          } else {
             bodyHtml = bodyHtml + visualBlock;
          }
        }

        htmlContent = `
          <div style="font-family: 'Segoe UI', Arial, sans-serif; color: #1e293b; line-height: 1.6; font-size: 11.5pt;">
            ${bodyHtml}
          </div>
        `;
      } else {
        // WhatsApp logic - HTML for clipboard (preview only, plain text is main)
        const footerHtml = config.footer.replace(/\n/g, '<br>');
        let textBefore = editableMessage.replace(/\n/g, '<br>');
        htmlContent = `<div style="font-family: sans-serif;">${textBefore}</div>`;
      }

      // Texto plano sin el marcador interno
      const plainText = editableMessage.replace('[ FIRMA PROFESIONAL ]', '');

      try {
        const data = [new ClipboardItem({
          'text/plain': new Blob([plainText], { type: 'text/plain' }),
          'text/html': new Blob([htmlContent], { type: 'text/html' })
        })];
        await navigator.clipboard.write(data);
      } catch (e) {
        await navigator.clipboard.writeText(plainText);
      }

      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);

      if (method === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        // Outlook Clásico:
        // Abrimos el correo vacío con asunto y destinatario.
        // El usuario DEBE presionar CTRL+V para pegar el contenido formateado.
        const subject = encodeURIComponent(client.deliveryFormat === 'pdf' ? "Adjunto Catálogos PDF" : "Adjunto Catálogo Digital");

        // Usamos mailto sin body para forzar al usuario a pegar y así no perder el formato HTML/Imágenes/Firma.
        window.location.href = `mailto:${client.email}?subject=${subject}`;
      }
    } catch (err) {
      console.error('Error al compartir:', err);
      alert('Error al copiar al portapapeles. Intenta nuevamente.');
    }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-48 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm font-medium">Previsualización de Mensaje</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[400px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3 flex items-center justify-between">
        <h2 className="font-bold text-slate-700 text-sm flex items-center gap-2">
          <MessageCircle className="w-4 h-4" />
          Vista Previa {client.sendMethod === 'email' ? '(Email)' : '(WhatsApp)'}
          <span className="text-[10px] bg-amber-100 text-amber-700 px-2 py-0.5 rounded ml-2 uppercase font-bold tracking-tight">
            {client.deliveryFormat === 'pdf' ? 'PDFs Adjuntos' : 'Enlace Web'}
          </span>
        </h2>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden">
        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className={`w-full flex-grow p-4 rounded-lg border-none focus:ring-0 text-slate-900 text-base lg:text-lg leading-relaxed font-sans resize-none transition-colors ${
            client.sendMethod === 'whatsapp' ? 'bg-[#DCF8C6]' : 'bg-indigo-50/50'
          }`}
          spellCheck="false"
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={() => handleCopyAndShare(client.sendMethod)}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : (client.sendMethod === 'email' ? 'Copiar y Abrir Outlook' : 'Copiar y abrir WhatsApp')}
        </button>
        <p className="text-[10px] text-slate-400 text-center mt-2 font-medium">
          {client.sendMethod === 'email' 
            ? 'Copiado al portapapeles. Al abrir Outlook, presiona CTRL+V en el mensaje.' 
            : 'Copiado para WhatsApp. Adjunta la foto manualmente.'}
        </p>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BookOpen, Share2, CheckCircle2 } from 'lucide-react';
import { ClientManager } from './components/ClientManager';
import { MessagePreview } from './components/MessagePreview';
import { VideoTutorial } from './components/VideoTutorial';
import { ClientData } from './types';

function App() {
  const [currentClient, setCurrentClient] = useState<ClientData | null>(null);
  const [savedClients, setSavedClients] = useState<ClientData[]>([]);

  useEffect(() => {
    const storedClients = localStorage.getItem('infema_v2_clients_vendedores');
    if (storedClients) {
      try { setSavedClients(JSON.parse(storedClients)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('infema_v2_clients_vendedores', JSON.stringify(savedClients));
  }, [savedClients]);

  const handleAddClient = (client: ClientData) => {
    setCurrentClient(client);
    setSavedClients(prev => {
      const existsIdx = prev.findIndex(c => 
        (client.sendMethod === 'whatsapp' ? c.phone === client.phone : c.email === client.email) && 
        c.seller === client.seller
      );
      if (existsIdx !== -1) {
        const updated = [...prev];
        updated[existsIdx] = client;
        return updated;
      }
      return [client, ...prev].slice(0, 100);
    });
  };

  const handleDeleteClient = (idToDelete: string) => {
    setSavedClients(prev => prev.filter(c => c.id !== idToDelete));
    if (currentClient?.id === idToDelete) {
      setCurrentClient(null);
    }
  };

  const handleExportClients = () => {
    if (savedClients.length === 0) {
      alert("No hay clientes guardados para exportar.");
      return;
    }

    const headers = ['Nombre Contacto', 'Empresa', 'Género', 'Vendedor', 'Medio', 'Teléfono', 'Email'];
    const rows = savedClients.map(client => [
      client.name || '',
      client.company,
      client.gender,
      client.seller,
      client.sendMethod,
      client.sendMethod === 'whatsapp' ? client.phone : '',
      client.sendMethod === 'email' ? client.email : ''
    ]);

    const csvContent = "\uFEFF" 
      + [headers.join(';'), ...rows.map(row => row.join(';'))].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);

    link.setAttribute('href', url);
    link.setAttribute('download', `clientes_infema_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col min-h-full">
      <header className="bg-[#1e293b] text-white shadow-md sticky top-0 z-50 safe-top flex-shrink-0">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-amber-500/20 p-1 rounded">
              <BookOpen className="w-5 h-5 text-amber-200" />
            </div>
            <h1 className="text-lg font-bold tracking-tight text-amber-50">INFEMA</h1>
          </div>
          <div className="flex items-center gap-3">
            <div className="text-[10px] font-medium text-slate-400 uppercase tracking-widest">
              Catálogos V2.2
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 py-4 sm:py-6">
        <VideoTutorial />

        <div className="grid lg:grid-cols-2 gap-4 sm:gap-6">
          <div className="space-y-4">
            <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 shadow-sm">
              <h2 className="text-amber-900 font-bold text-xs uppercase tracking-wider mb-3 flex items-center gap-2">
                <Share2 className="w-4 h-4" />
                Resumen de Envío
              </h2>
              <div className="space-y-2">
                <div className="flex items-start gap-2 text-[11px] text-amber-800">
                  <CheckCircle2 className="w-3.5 h-3.5 text-amber-600 mt-0.5 shrink-0" />
                  <span>1. Selecciona Vendedor y Medio.</span>
                </div>
                <div className="flex items-start gap-2 text-[11px] text-amber-800">
                  <CheckCircle2 className="w-3.5 h-3.5 text-amber-600 mt-0.5 shrink-0" />
                  <span>2. Completa los datos del cliente.</span>
                </div>
                <div className="flex items-start gap-2 text-[11px] text-amber-800">
                  <CheckCircle2 className="w-3.5 h-3.5 text-amber-600 mt-0.5 shrink-0" />
                  <span>3. Generar, Copiar y Pegar en tu App de envío.</span>
                </div>
              </div>
            </div>

            <ClientManager 
              onClientSelect={handleAddClient} 
              savedClients={savedClients}
              onDeleteClient={handleDeleteClient}
              currentClientId={currentClient?.id}
              onExportClients={handleExportClients}
            />
          </div>

          <div className="h-full">
             <MessagePreview client={currentClient} />
          </div>
        </div>
      </main>
    </div>
  );
}

