    setName(client.name);
    setLastName(client.lastName || '');
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
