interface MessagePreviewProps {
  client: ClientData | null;
}

export const MessagePreview: React.FC<MessagePreviewProps> = ({ client }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  const generateCID = (client: ClientData) => {
    if (client.sendMethod === 'whatsapp') {
      const cleanPhone = client.phone.replace('+569', '');
      return cleanPhone.slice(0, -1);
    } else {
      const email = client.email || '';
      const parts = email.split('@');
      if (parts.length === 2) {
        const pre = parts[0].substring(0, 3);
        const post = parts[1].substring(0, 3);
        return `${pre}.${post}`.toLowerCase();
      }
      return "user.inf";
    }
  };

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      const cid = generateCID(client);
      let salutation = client.name 
        ? `👋 Hola ${client.gender === 'hombre' ? 'D.' : 'Sra.'} ${client.name},` 
        : `${client.company}.\nEstimado cliente,`;

      const connector = config.link.includes('?') ? '&' : '?';
      const fullLink = `${config.link}${connector}cid=${cid}`;

      let mainText = "";
      if (client.deliveryFormat === 'pdf') {
        mainText = "Adjunto PDFs de Catálogo.";
      } else {
        mainText = "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";
      }

      let bodyText = "";
      if (client.sendMethod === 'email') {
        if (client.deliveryFormat === 'pdf') {
          // Orden solicitado: Saludo -> Espacio -> Texto -> Espacio -> Saludo Final -> [Firma]
          bodyText = `${salutation}\n\n${mainText}\n\n${config.footer}\n\n[FIRMA_WIS_PDF]`;
        } else {
          // Formato ENLACE (Sin firma Wisestamp)
          bodyText = client.seller === 'OF'
            ? `${salutation}\n\n${mainText}\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n[ELEMENTO_ENLACE]`
            : `${salutation}\n\n${mainText}\n\n[ELEMENTO_ENLACE]`;
        }
      } else {
        // WhatsApp
        if (client.deliveryFormat === 'pdf') {
          bodyText = `${salutation}\n\n${mainText}\n\n${config.footer}`;
        } else {
          bodyText = client.seller === 'OF'
            ? `${salutation}\n\n${mainText}\n─────────────\n🔗 ${fullLink}\n─────────────\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`
            : `${salutation}\n\n${mainText}\n─────────────\n🔗 ${fullLink}\n─────────────\n\n${config.footer}`;
        }
      }

      setEditableMessage(bodyText);
    }
  }, [client]);

  const handleCopyAndShare = async () => {
    if (!client || !editableMessage) return;

    const config = SELLER_CONFIG[client.seller];
    const cid = generateCID(client);
    const connector = config.link.includes('?') ? '&' : '?';
    const clientLink = `${config.link}${connector}cid=${cid}`;

    try {
      const plainText = editableMessage.replace('[ELEMENTO_ENLACE]', '').replace('[FIRMA_WIS_PDF]', '');
      let bodyHtml = editableMessage.replace(/\n/g, '<br>');

      if (client.sendMethod === 'email') {
        const footerHtml = config.footer.replace(/\n/g, '<br>');
        const dynamicSignature = getDynamicSignature(cid);

        if (client.deliveryFormat === 'link') {
          // FOTO vinculada -> Espacio -> Saludo Final (SIN firma Wisestamp)
          const visualBlock = `
            <div style="margin: 25px 0;">
              <a href="${clientLink}" target="_blank" style="text-decoration: none; border: 0;">
                <img src="${config.image}" width="550" alt="Ver Catálogo" style="width: 550px; max-width: 100%; border: 0; display: block; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.1);">
              </a>
            </div>
          `;
          const emailSection = `${visualBlock}<br><br>${footerHtml}`;
          bodyHtml = bodyHtml.replace('[ELEMENTO_ENLACE]', emailSection);
        } else {
          // PDF: Ya tiene el texto y el footer en el cuerpo, solo insertamos la firma al final.
          bodyHtml = bodyHtml.replace('[FIRMA_WIS_PDF]', dynamicSignature);
        }
      }

      const finalHtml = `
        <html>
          <head><meta charset="UTF-8"></head>
          <body>
            <div style="font-family: 'Segoe UI', Arial, sans-serif; color: #2d3748; line-height: 1.6; font-size: 12pt;">
              ${bodyHtml}
            </div>
          </body>
        </html>
      `;

      const data = [new ClipboardItem({
        'text/plain': new Blob([plainText], { type: 'text/plain' }),
        'text/html': new Blob([finalHtml], { type: 'text/html' })
      })];

      await navigator.clipboard.write(data);
      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);

      if (client.sendMethod === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        const subjectLine = client.deliveryFormat === 'pdf' ? `Adjunto PDFs - ${client.company}` : `Catálogo Digital - ${client.company}`;
        window.location.href = `mailto:${client.email}?subject=${encodeURIComponent(subjectLine)}`;
      }
    } catch (err) {
      console.error('Error al copiar:', err);
      alert('Error al copiar. Intenta nuevamente.');
    }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-64 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm">Selecciona un cliente para ver la previa</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[450px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3 flex items-center justify-between">
        <h2 className="font-bold text-slate-700 text-sm flex items-center gap-2">
          <MessageCircle className="w-4 h-4" />
          Previsualización {client.sendMethod === 'email' ? 'Email' : 'WhatsApp'}
        </h2>
        <div className="text-[10px] font-bold text-amber-600 bg-amber-50 px-2 py-0.5 rounded border border-amber-100 uppercase">
          {client.deliveryFormat === 'pdf' ? 'Formato PDFs' : 'Formato Enlace'}
        </div>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden">
        <div className={`flex-grow p-4 rounded-lg text-slate-900 text-sm lg:text-base leading-relaxed overflow-y-auto ${
          client.sendMethod === 'whatsapp' ? 'bg-[#e5ddd5]' : 'bg-slate-50'
        }`}>
          <div className="whitespace-pre-wrap font-sans">
             {editableMessage.split(/\[ELEMENTO_ENLACE\]|\[FIRMA_WIS_PDF\]/).map((part, i) => (
               <React.Fragment key={i}>
                 {part}
                 {i === 0 && client.sendMethod === 'email' && (
                   <div className="my-6 border-l-4 border-amber-400 pl-4 bg-white/40 py-4">
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mb-4 italic">Contenido automático:</p>
                     <div className="flex flex-col gap-4">
                        {client.deliveryFormat === 'link' ? (
                          <>
                            <div className="flex items-center gap-4 bg-white p-2 rounded shadow-sm border border-slate-100">
                              <img src={SELLER_CONFIG[client.seller].image} className="w-24 h-16 object-cover rounded" alt="Catálogo" />
                              <p className="text-xs font-bold text-slate-600">Imagen vinculada</p>
                            </div>
                            <p className="text-xs text-slate-400 italic">Saludos, Lorena Barros (Sin firma Wisestamp)</p>
                          </>
                        ) : (
                          <>
                            <div className="bg-slate-100 p-2 rounded border border-slate-200 text-center">
                              <p className="text-[9px] font-bold text-slate-400 uppercase">Firma Wisestamp con ID</p>
                            </div>
                            <p className="text-xs text-slate-400 italic">Insertada al final de "Saludos, Lorena Barros"</p>
                          </>
                        )}
                     </div>
                   </div>
                 )}
               </React.Fragment>
             ))}
          </div>
        </div>
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={handleCopyAndShare}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Contenido Copiado!' : (client.sendMethod === 'email' ? 'Copiar y Abrir Outlook' : 'Copiar y abrir WhatsApp')}
        </button>
      </div>
    </div>
  );
};

