  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  const generateCID = (client: ClientData) => {
    if (client.sendMethod === 'whatsapp') {
      const cleanPhone = client.phone.replace('+569', '');
      return cleanPhone.slice(0, -1);
    } else {
      const email = client.email || '';
      const parts = email.split('@');
      if (parts.length === 2) {
        const pre = parts[0].substring(0, 3);
        const post = parts[1].substring(0, 3);
        return `${pre}.${post}`.toLowerCase();
      }
      return "user.inf";
    }
  };

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      const cid = generateCID(client);
      let salutation = client.name 
        ? `👋 Hola ${client.gender === 'hombre' ? 'D.' : 'Sra.'} ${client.name},` 
        : `${client.company}.\nEstimado cliente,`;

      const connector = config.link.includes('?') ? '&' : '?';
      const fullLink = `${config.link}${connector}cid=${cid}`;

      let mainText = client.deliveryFormat === 'pdf' ? "Adjunto PDFs de Catálogo." : "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";

      let bodyText = "";
      if (client.sendMethod === 'email') {
        if (client.deliveryFormat === 'pdf') {
          const sigPlaceholder = client.seller === 'OF' ? "\n\n[FIRMA_WIS_PDF]" : "";
          bodyText = `${salutation}\n\n${mainText}\n\n${config.footer}${sigPlaceholder}`;
        } else {
          bodyText = client.seller === 'OF'
            ? `${salutation}\n\n${mainText}\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n[ELEMENTO_ENLACE]`
            : `${salutation}\n\n${mainText}\n\n[ELEMENTO_ENLACE]`;
        }
      } else {
        if (client.deliveryFormat === 'pdf') {
          const signaturePart = (client.seller === 'OF') ? `\n\n${getTextSignature(cid)}` : `\n\n${config.footer}`;
          bodyText = `${salutation}\n\n${mainText}${signaturePart}`;
        } else {
          bodyText = client.seller === 'OF'
            ? `${salutation}\n\n${mainText}\n─────────────\n🔗 ${fullLink}\n─────────────\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`
            : `${salutation}\n\n${mainText}\n─────────────\n🔗 ${fullLink}\n─────────────\n\n${config.footer}`;
        }
      }
      setEditableMessage(bodyText);
    }
  }, [client]);

  const handleCopyAndShare = async () => {
    if (!client || !editableMessage) return;
    const config = SELLER_CONFIG[client.seller];
    const cid = generateCID(client);
    const connector = config.link.includes('?') ? '&' : '?';
    const clientLink = `${config.link}${connector}cid=${cid}`;
    try {
      const currentText = editableMessage;
      const plainText = currentText.replace('[ELEMENTO_ENLACE]', '').replace('[FIRMA_WIS_PDF]', '');
      let bodyHtml = currentText.replace(/\n/g, '<br>');
      if (client.sendMethod === 'email') {
        const footerHtml = config.footer.replace(/\n/g, '<br>');
        const dynamicSignature = getDynamicSignature(cid);
        if (client.deliveryFormat === 'link') {
          const visualBlock = `<div style="margin: 25px 0;"><a href="${clientLink}" target="_blank" style="text-decoration: none; border: 0;"><img src="${config.image}" width="550" alt="Ver Catálogo" style="width: 550px; max-width: 100%; border: 0; display: block; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.1);"></a></div>`;
          const emailSection = `${visualBlock}<br><br>${footerHtml}`;
          bodyHtml = bodyHtml.replace('[ELEMENTO_ENLACE]', emailSection);
        } else {
          bodyHtml = bodyHtml.replace('[FIRMA_WIS_PDF]', client.seller === 'OF' ? dynamicSignature : "");
        }
      }
      const finalHtml = `<html><head><meta charset="UTF-8"></head><body><div style="font-family: 'Segoe UI', Arial, sans-serif; color: #2d3748; line-height: 1.6; font-size: 12pt;">${bodyHtml}</div></body></html>`;
      const data = [new ClipboardItem({
        'text/plain': new Blob([plainText], { type: 'text/plain' }),
        'text/html': new Blob([finalHtml], { type: 'text/html' })
      })];
      await navigator.clipboard.write(data);
      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);
      if (client.sendMethod === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        const subjectLine = client.deliveryFormat === 'pdf' ? `Adjunto PDFs - ${client.company}` : `Catálogo Digital - ${client.company}`;
        window.location.href = `mailto:${client.email}?subject=${encodeURIComponent(subjectLine)}`;
      }
    } catch (err) { console.error('Error al copiar:', err); }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-64 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm">Selecciona un cliente para ver la previa</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[500px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3 flex items-center">
        <Edit3 className="w-4 h-4 text-amber-600 mr-2" />
        <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">Personalización del Mensaje</span>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden bg-slate-50">
        {client.deliveryFormat === 'pdf' && (
          <div className="mb-3 p-3 bg-amber-50 border border-amber-200 rounded-lg flex gap-3 items-start shadow-sm">
            <AlertCircle className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
            <p className="text-[11px] leading-tight text-amber-900">
              <b>RECORDATORIO PDFS:</b> Pega y envía este <b>texto primero</b>. Luego adjunta los archivos en WhatsApp Web usando el botón "+" -> "Documento".
            </p>
          </div>
        )}

        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className={`w-full h-full p-4 rounded-lg text-slate-900 text-sm lg:text-base leading-relaxed resize-none focus:ring-2 focus:ring-amber-500 outline-none border transition-colors ${
            client.sendMethod === 'whatsapp' ? 'bg-[#e5ddd5] border-[#d1d7db]' : 'bg-white border-slate-200 shadow-inner'
          }`}
          placeholder="Escribe tu mensaje aquí..."
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={handleCopyAndShare}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : (client.sendMethod === 'email' ? 'Copiar y abrir EMAIL' : 'Copiar y abrir WhatsApp')}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { UserPlus, Briefcase, Phone, User, History, Trash2, UserCheck, Mail, Send, Users, Download, FileText, Link } from 'lucide-react';
import { ClientData, SellerType, SendMethod, GenderType, DeliveryFormat } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  onExportClients: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  onExportClients
}) => {
  const [name, setName] = useState('');
  const [lastName, setLastName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('hombre');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('OF');
  const [sendMethod, setSendMethod] = useState<SendMethod>('whatsapp');
  const [deliveryFormat, setDeliveryFormat] = useState<DeliveryFormat>('link');

  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido (+569XXXXXXXX)');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!company.trim()) {
      alert('El Nombre Comercial es obligatorio.');
      return;
    }
    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: Date.now().toString(),
      name: name.trim(),
      lastName: lastName.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod,
      deliveryFormat
    };
    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setLastName(client.lastName || '');
    setCompany(client.company || '');
    setGender(client.gender || 'hombre');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || 'whatsapp');
    setDeliveryFormat(client.deliveryFormat || 'link');
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-4">

          <div className="mb-6">
            <label className="block text-sm font-bold text-amber-800 mb-2 uppercase tracking-tight">Formato de Envío</label>
            <div className="grid grid-cols-2 gap-2">
              <button
                type="button"
                onClick={() => setDeliveryFormat('link')}
                className={`flex items-center justify-center gap-2 py-2 px-4 rounded-lg border-2 transition-all font-bold text-sm ${
                  deliveryFormat === 'link' 
                    ? 'border-amber-600 bg-amber-50 text-amber-700' 
                    : 'border-slate-200 bg-white text-slate-500 hover:bg-slate-50'
                }`}
              >
                <Link className="w-4 h-4" />
                Enlace Web
              </button>
              <button
                type="button"
                onClick={() => setDeliveryFormat('pdf')}
                className={`flex items-center justify-center gap-2 py-2 px-4 rounded-lg border-2 transition-all font-bold text-sm ${
                  deliveryFormat === 'pdf' 
                    ? 'border-amber-600 bg-amber-50 text-amber-700' 
                    : 'border-slate-200 bg-white text-slate-500 hover:bg-slate-50'
                }`}
              >
                <FileText className="w-4 h-4" />
                PDFs Adjuntos
              </button>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="OF">OF</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Medio de Envío</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => {
                    const newMethod = e.target.value as SendMethod;
                    setSendMethod(newMethod);
                    // Limpieza de campos al cambiar de medio
                    setPhone('');
                    setEmail('');
                    setPhoneError('');
                    setEmailError('');
                  }}
                  className="w-full pl-10 pr-4 py-2 bg-slate-800 border border-slate-700 text-white rounded-lg focus:ring-2 focus:ring-amber-500 outline-none transition-all appearance-none font-bold"
                >
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">Email</option>
                </select>
              </div>
            </div>
          </div>

          <h2 className="text-lg font-bold text-slate-800 pt-2 flex items-center gap-2 border-t border-slate-100 mt-4">
            <UserPlus className="w-5 h-5 text-amber-700" />
            Datos del Cliente
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Género</label>
              <div className="relative">
                <Users className="absolute left-3 top-2.5 w-5 h-5 text-slate-400 z-10" />
                <select
                  value={gender}
                  onChange={(e) => setGender(e.target.value as GenderType)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none appearance-none text-slate-900 bg-white font-medium"
                >
                  <option value="hombre">Hombre (D.)</option>
                  <option value="mujer">Mujer (Sra.)</option>
                </select>
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nombre</label>
              <div className="relative">
                <User className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 bg-white font-medium"
                  placeholder="Ej: Juan"
                />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Apellido</label>
              <div className="relative">
                <User className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                <input
                  type="text"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 bg-white font-medium"
                  placeholder="Ej: Pérez"
                />
              </div>
            </div>
            <div>
              {sendMethod === 'whatsapp' ? (
                <>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Teléfono (+569...)</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                    <input
                      type="tel"
                      value={phone}
                      onChange={handlePhoneChange}
                      className={`w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 bg-white font-medium ${
                        phoneError ? 'border-red-500 bg-red-50' : 'border-slate-400'
                      }`}
                      placeholder="+56912345678"
                      required
                    />
                  </div>
                </>
              ) : (
                <>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Correo Electrónico</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
                    <input
                      type="email"
                      value={email}
                      onChange={handleEmailChange}
                      className={`w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 bg-white font-medium ${
                        emailError ? 'border-red-500 bg-red-50' : 'border-slate-400'
                      }`}
                      placeholder="cliente@empresa.com"
                      required
                    />
                  </div>
                </>
              )}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Comercial (requerido)</label>
            <div className="relative">
              <Briefcase className="absolute left-3 top-2.5 w-5 h-5 text-slate-400" />
              <input
                type="text"
                value={company}
                onChange={(e) => setCompany(e.target.value)}
                required
                className="w-full pl-10 pr-4 py-2 border border-slate-400 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 bg-white font-medium"
                placeholder="Ej.: Razón social o Nombre de Tienda/Negocio"
              />
            </div>
          </div>

          <div className="pt-2">
            <button
              type="submit"
              className="w-full bg-amber-700 hover:bg-amber-800 text-white font-bold py-3 rounded-lg transition-all shadow-md active:transform active:scale-95"
            >
              Generar y Guardar
            </button>
          </div>
        </form>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 overflow-hidden flex flex-col max-h-[400px]">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <History className="w-5 h-5 text-amber-700" />
            Clientes Guardados
          </h2>
          {savedClients.length > 0 && (
            <button
              onClick={onExportClients}
              className="flex items-center gap-1 text-[10px] font-bold bg-green-100 text-green-700 px-2 py-1 rounded hover:bg-green-200"
            >
              <Download className="w-3 h-3" />
              Excel
            </button>
          )}
        </div>

        <div className="flex-grow overflow-y-auto space-y-2 -mx-2 px-2">
          {savedClients.map((client) => (
            <div 
              key={client.id}
              className={`group flex items-center justify-between p-3 rounded-lg border transition-all cursor-pointer ${
                currentClientId === client.id ? 'bg-amber-50 border-amber-200 shadow-sm' : 'bg-white border-slate-100 hover:border-amber-200 hover:bg-slate-50'
              }`}
              onClick={() => loadClient(client)}
            >
              <div className="flex-grow min-w-0 pr-4">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-bold bg-amber-100 text-amber-800 px-1.5 py-0.5 rounded">{client.seller}</span>
                  <p className="font-semibold text-slate-800 text-sm truncate">{client.company}</p>
                </div>
              </div>
              <button
                onClick={(e) => { e.stopPropagation(); onDeleteClient(client.id); }}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-red-500"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

