import React, { useState, useEffect } from 'react';
import { Mail, Send, Info } from 'lucide-react';
import { ClientManager } from './components/ClientManager';
import { MessagePreview } from './components/MessagePreview';
import { ClientData } from './types';

function App() {
  const [currentClient, setCurrentClient] = useState<ClientData | null>(null);
  const [savedClients, setSavedClients] = useState<ClientData[]>([]);

  useEffect(() => {
    const storedClients = localStorage.getItem('infema_v2_clients_vendedores');
    if (storedClients) {
      try { setSavedClients(JSON.parse(storedClients)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('infema_v2_clients_vendedores', JSON.stringify(savedClients));
  }, [savedClients]);

  const handleAddClient = (client: ClientData) => {
    setSavedClients(prev => {
      const existsIdx = prev.findIndex(c => 
        c.seller === client.seller && 
        c.company.toLowerCase().trim() === client.company.toLowerCase().trim()
      );

      let updatedList;
      if (existsIdx !== -1) {
        const updated = [...prev];
        const existingClient = updated[existsIdx];
        const mergedClient = {
          ...client,
          id: existingClient.id,
          lastSentMethod: client.sendMethod
        };
        updated.splice(existsIdx, 1);
        updatedList = [mergedClient, ...updated];
        setCurrentClient(mergedClient);
      } else {
        const newClient = { ...client, lastSentMethod: client.sendMethod };
        updatedList = [newClient, ...prev].slice(0, 100);
        setCurrentClient(newClient);
      }
      return updatedList;
    });
  };

  const handleDeleteClient = (idToDelete: string) => {
    setSavedClients(prev => prev.filter(c => c.id !== idToDelete));
    if (currentClient?.id === idToDelete) {
      setCurrentClient(null);
    }
  };

  const handleExportClients = () => {
    if (savedClients.length === 0) {
      alert("No hay clientes guardados para exportar.");
      return;
    }
    const headers = ['Nombre Contacto', 'Empresa', 'Género', 'Vendedor', 'Medio', 'Teléfono', 'Email', 'Último Envío'];
    const rows = savedClients.map(client => [
      client.name || '',
      client.company,
      client.gender,
      client.seller,
      client.sendMethod,
      client.phone || '',
      client.email || '',
      client.lastSentMethod || 'Pendiente'
    ]);
    const csvContent = "\uFEFF" + [headers.join(';'), ...rows.map(row => row.join(';'))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `clientes_infema_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col min-h-full bg-slate-50">
      <header className="bg-[#1e293b] text-white shadow-md sticky top-0 z-50 safe-top flex-shrink-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-lg shadow-sm overflow-hidden flex items-center justify-center w-10 h-10">
              <img 
                src="https://assets.zyrosite.com/AE04NxxDXof684vj/catalogo-infema---acceso-clientes-iwSY3YftcmWoi3OY.jpg" 
                alt="INFEMA Logo" 
                className="w-full h-full object-cover"
              />
            </div>
