interface MessagePreviewProps {
  client: ClientData | null;
}

export const MessagePreview: React.FC<MessagePreviewProps> = ({ client }) => {
  const [editableMessage, setEditableMessage] = useState('');
  const [justCopied, setJustCopied] = useState(false);

  const generateCID = (client: ClientData) => {
    if (client.sendMethod === 'whatsapp') {
      const cleanPhone = client.phone.replace('+569', '');
      return cleanPhone.slice(0, -1);
    } else {
      const email = client.email || '';
      const parts = email.split('@');
      if (parts.length === 2) {
        const pre = parts[0].substring(0, 3);
        const post = parts[1].substring(0, 3);
        return `${pre}.${post}`.toLowerCase();
      }
      return "user.inf";
    }
  };

  useEffect(() => {
    if (client) {
      const config = SELLER_CONFIG[client.seller];
      const cid = generateCID(client);

      // Saludo dinámico manejando género opcional
      const genderPrefix = client.gender === 'hombre' ? 'D. ' : client.gender === 'mujer' ? 'Sra. ' : '';
      let salutation = client.name 
        ? `👋 Hola ${genderPrefix}${client.name},` 
        : `${client.company}.\nEstimado cliente,`;

      const connector = config.link.includes('?') ? '&' : '?';
      const fullLink = `${config.link}${connector}cid=${cid}`;

      let mainText = client.deliveryFormat === 'pdf' 
        ? "ADJUNTO PDFs." 
        : "📖 Le comparto el enlace directo al catálogo en línea (aquí lo estaremos actualizando):";

      let bodyText = "";
      if (client.sendMethod === 'email') {
        if (client.deliveryFormat === 'pdf') {
          const sigPlaceholder = client.seller === 'OF' ? "\n\n[FIRMA_WIS_PDF]" : "";
          bodyText = `${salutation}\n\n${mainText}\n\n${config.footer}${sigPlaceholder}`;
        } else {
          bodyText = client.seller === 'OF'
            ? `${salutation}\n\n${mainText}\n\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n[ELEMENTO_ENLACE]`
            : `${salutation}\n\n${mainText}\n\n[ELEMENTO_ENLACE]`;
        }
      } else {
        if (client.deliveryFormat === 'pdf') {
          const signaturePart = (client.seller === 'OF') ? `\n\n${getTextSignature(cid)}` : `\n${config.footer}`;
          bodyText = `${salutation}\n\n${mainText}${signaturePart}`;
        } else {
          bodyText = client.seller === 'OF'
            ? `${salutation}\n\n${mainText}\n─────────────\n🔗 ${fullLink}\n─────────────\n📌 Para entrar la primera vez por favor use el nombre de Usuario y Contraseña que aparecen en la foto.\n\n${config.footer}`
            : `${salutation}\n\n${mainText}\n─────────────\n🔗 ${fullLink}\n─────────────\n${config.footer}`;
        }
      }
      setEditableMessage(bodyText);
    }
  }, [client]);

  const handleCopyAndShare = async () => {
    if (!client || !editableMessage) return;
    const config = SELLER_CONFIG[client.seller];
    const cid = generateCID(client);
    const connector = config.link.includes('?') ? '&' : '?';
    const clientLink = `${config.link}${connector}cid=${cid}`;
    try {
      const currentText = editableMessage;
      const plainText = currentText.replace('[ELEMENTO_ENLACE]', '').replace('[FIRMA_WIS_PDF]', '');
      let bodyHtml = currentText.replace(/\n/g, '<br>');
      if (client.sendMethod === 'email') {
        const footerHtml = config.footer.replace(/\n/g, '<br>');
        const dynamicSignature = getDynamicSignature(cid);
        if (client.deliveryFormat === 'link') {
          const visualBlock = `<div style="margin: 25px 0;"><a href="${clientLink}" target="_blank" style="text-decoration: none; border: 0;"><img src="${config.image}" width="550" alt="Ver Catálogo" style="width: 550px; max-width: 100%; border: 0; display: block; border-radius: 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.1);"></a></div>`;
          const emailSection = `${visualBlock}<br>${footerHtml}`;
          bodyHtml = bodyHtml.replace('[ELEMENTO_ENLACE]', emailSection);
        } else {
          bodyHtml = bodyHtml.replace('[FIRMA_WIS_PDF]', client.seller === 'OF' ? dynamicSignature : "");
        }
      }
      const finalHtml = `<html><head><meta charset="UTF-8"></head><body><div style="font-family: 'Segoe UI', Arial, sans-serif; color: #2d3748; line-height: 1.6; font-size: 12pt;">${bodyHtml}</div></body></html>`;
      const data = [new ClipboardItem({
        'text/plain': new Blob([plainText], { type: 'text/plain' }),
        'text/html': new Blob([finalHtml], { type: 'text/html' })
      })];
      await navigator.clipboard.write(data);
      setJustCopied(true);
      setTimeout(() => setJustCopied(false), 2000);
      if (client.sendMethod === 'whatsapp') {
        window.open(`https://wa.me/${client.phone.replace('+', '')}`, '_blank');
      } else {
        const subjectLine = client.deliveryFormat === 'pdf' ? "Adjunto PDFs." : "Adjunto Catálogo Digital";
        window.location.href = `mailto:${client.email}?subject=${encodeURIComponent(subjectLine)}`;
      }
    } catch (err) { console.error('Error al copiar:', err); }
  };

  if (!client) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 h-64 flex flex-col items-center justify-center p-6 text-center text-slate-400">
        <Info className="w-8 h-8 mb-2 opacity-20" />
        <p className="text-sm">Selecciona un cliente para ver la previa</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full min-h-[500px]">
      <div className="bg-slate-50 border-b border-slate-200 p-3 flex items-center">
        <Edit3 className="w-4 h-4 text-amber-600 mr-2" />
        <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">Personalización del Mensaje</span>
      </div>

      <div className="flex-grow p-4 flex flex-col overflow-hidden bg-slate-50">
        <textarea
          value={editableMessage}
          onChange={(e) => setEditableMessage(e.target.value)}
          className={`w-full h-full p-4 rounded-lg text-slate-900 text-sm lg:text-base leading-relaxed resize-none focus:ring-2 focus:ring-amber-500 outline-none border transition-colors ${
            client.sendMethod === 'whatsapp' ? 'bg-[#e5ddd5] border-[#d1d7db]' : 'bg-white border-slate-200 shadow-inner'
          }`}
          placeholder="Escribe tu mensaje aquí..."
        />
      </div>

      <div className="p-3 bg-slate-50 border-t border-slate-200">
        <button
          onClick={handleCopyAndShare}
          className={`w-full flex items-center justify-center gap-2 py-3 text-white rounded-lg font-bold text-sm transition-all shadow-md active:scale-95 ${
            justCopied ? 'bg-green-600' : (client.sendMethod === 'whatsapp' ? 'bg-[#25D366]' : 'bg-indigo-600')
          }`}
        >
          <ClipboardCheck className="w-5 h-5" />
          {justCopied ? '¡Copiado!' : (client.sendMethod === 'email' ? 'Copiar y abrir Email' : 'Copiar y abrir WhatsApp')}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Mail, Send, Info } from 'lucide-react';
import { ClientManager } from './components/ClientManager';
import { MessagePreview } from './components/MessagePreview';
import { ClientData } from './types';

function App() {
  const [currentClient, setCurrentClient] = useState<ClientData | null>(null);
  const [savedClients, setSavedClients] = useState<ClientData[]>([]);

  useEffect(() => {
    const storedClients = localStorage.getItem('infema_v2_clients_vendedores');
    if (storedClients) {
      try { setSavedClients(JSON.parse(storedClients)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('infema_v2_clients_vendedores', JSON.stringify(savedClients));
  }, [savedClients]);

  const handleAddClient = (client: ClientData) => {
    setSavedClients(prev => {
      // 1. Identificar si el cliente ya existe (por ID o por la combinación única de Vendedor y Empresa)
      const existsIdx = prev.findIndex(c => 
        c.id === client.id || 
        (c.seller === client.seller && c.company.toLowerCase().trim() === client.company.toLowerCase().trim())
      );

      // 2. Crear la lista filtrada eliminando el duplicado si existe
      const filteredList = prev.filter((_, idx) => idx !== existsIdx);

      // 3. Preparar el cliente actualizado (preservando el ID original si hubo coincidencia)
      const finalClient: ClientData = {
        ...client,
        id: existsIdx !== -1 ? prev[existsIdx].id : (client.id || Date.now().toString()),
        lastSentMethod: client.sendMethod
      };

      // 4. Colocarlo al principio de la lista y limitar a los últimos 100
      const updatedList = [finalClient, ...filteredList].slice(0, 100);

      setCurrentClient(finalClient);
      return updatedList;
    });
  };

  const handleDeleteClient = (idToDelete: string) => {
    setSavedClients(prev => prev.filter(c => c.id !== idToDelete));
    if (currentClient?.id === idToDelete) {
      setCurrentClient(null);
    }
  };

  const handleExportClients = () => {
    if (savedClients.length === 0) {
      alert("No hay clientes guardados para exportar.");
      return;
    }
    const headers = ['Nombre Contacto', 'Empresa', 'Género', 'Vendedor', 'Medio', 'Teléfono', 'Email', 'Último Envío'];
    const rows = savedClients.map(client => [
      client.name || '',
      client.company,
      client.gender,
      client.seller,
      client.sendMethod,
      client.phone || '',
      client.email || '',
      client.lastSentMethod || 'Pendiente'
    ]);
    const csvContent = "\uFEFF" + [headers.join(';'), ...rows.map(row => row.join(';'))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `clientes_infema_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col min-h-full bg-slate-50">
      <header className="bg-[#1e293b] text-white shadow-md sticky top-0 z-50 safe-top flex-shrink-0">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center">
            <h1 className="text-xl font-black tracking-tight text-white uppercase italic">INFEMA</h1>
          </div>
          <div className="flex items-center gap-3">
            <div className="text-[10px] font-bold text-amber-400 bg-amber-400/10 px-2 py-0.5 rounded border border-amber-400/20 uppercase tracking-widest">
              V2.5
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 py-6 space-y-6">
        {/* Tutorial de Envío Restablecido */}
        <section className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 px-6 py-3 flex items-center gap-2">
            <Info className="w-5 h-5 text-amber-400" />
            <h2 className="text-white font-bold text-sm tracking-wide uppercase">Tutorial de Envío</h2>
          </div>
          <div className="p-6 grid md:grid-cols-2 gap-8">
            {/* WhatsApp Tutorial */}
            <div className="space-y-4">
              <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                <Send className="w-5 h-5 text-[#25D366]" />
                <h3 className="font-bold text-slate-800 text-sm uppercase tracking-tight">Envíos por WhatsApp</h3>
              </div>
              <ul className="space-y-3">
                <li className="flex gap-3 items-start">
                  <div className="flex-shrink-0 w-5 h-5 bg-green-50 text-[#25D366] rounded-full flex items-center justify-center text-xs font-black">1</div>
                  <p className="text-xs text-slate-600 leading-relaxed">
                    Después de completar los datos y generar el mensaje (editable), hacer clic en <strong>Copiar y abrir WhatsApp</strong>.
                  </p>
                </li>
                <li className="flex gap-3 items-start">
                  <div className="flex-shrink-0 w-5 h-5 bg-green-50 text-[#25D366] rounded-full flex items-center justify-center text-xs font-black">2</div>
                  <p className="text-xs text-slate-600 leading-relaxed">
                    Una vez en el chat del cliente: Para formato de envío con <strong>LINK</strong>, primero adjunta la imagen correspondiente y luego pega el texto aquí generado. Para formato de envío como <strong>PDFs</strong>, pega el texto generado primero y en otro mensaje a continuación adjunta los archivos usando el botón <strong>"+" -> "Documento"</strong>.
                  </p>
                </li>
              </ul>
            </div>

            {/* Email Tutorial */}
            <div className="space-y-4">
              <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                <Mail className="w-5 h-5 text-indigo-600" />
                <h3 className="font-bold text-slate-800 text-sm uppercase tracking-tight">Envíos por Email</h3>
              </div>
              <ul className="space-y-3">
                <li className="flex gap-3 items-start">
                  <div className="flex-shrink-0 w-5 h-5 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center text-xs font-black">1</div>
                  <p className="text-xs text-slate-600 leading-relaxed">
                    Después de completar los datos y generar el mensaje (editable), hacer clic en <strong>Copiar y abrir Email</strong>.
                  </p>
                </li>
                <li className="flex gap-3 items-start">
                  <div className="flex-shrink-0 w-5 h-5 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center text-xs font-black">2</div>
                  <p className="text-xs text-slate-600 leading-relaxed">
                    En el cuerpo del mensaje, haz clic en <strong>Pegar</strong>. Para formato de envío con <strong>LINK</strong>, la imagen con enlace correspondiente se añadirá automáticamente. Para formato de envío como <strong>PDFs</strong>, haz clic en <strong>"Insertar"</strong> del menú del mensaje y luego <strong>"Adjuntar archivos"</strong>.
                  </p>
                </li>
              </ul>
            </div>
          </div>
        </section>

        <div className="grid lg:grid-cols-2 gap-6">
          <div className="space-y-6">
            <ClientManager 
              onClientSelect={handleAddClient} 
              savedClients={savedClients}
              onDeleteClient={handleDeleteClient}
              currentClientId={currentClient?.id}
              onExportClients={handleExportClients}
            />
          </div>

          <div className="h-full">
             <MessagePreview client={currentClient} />
          </div>
        </div>
      </main>

      <footer className="mt-auto py-4 text-center">
        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">INFEMA LTDA - Equipo de Ventas Interno</p>
      </footer>
    </div>
  );
}

