import React, { useState, useMemo } from 'react';
import { UserPlus, Briefcase, Phone, Trash2, UserCheck, Mail, Send, Link, FileText, History, Download, CheckCircle2 } from 'lucide-react';
import { ClientData, SellerType, SendMethod, GenderType, DeliveryFormat } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  onExportClients: () => void;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  onExportClients
}) => {
  const [name, setName] = useState('');
  const [lastName, setLastName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('');
  const [sendMethod, setSendMethod] = useState<SendMethod>('');
  const [deliveryFormat, setDeliveryFormat] = useState<DeliveryFormat>('link');

  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const existingClientRecord = useMemo(() => {
    if (!company.trim() || !seller) return null;
    return savedClients.find(c => 
      c.seller === seller && 
      c.company.toLowerCase().trim() === company.toLowerCase().trim()
    );
  }, [company, seller, savedClients]);

  const validatePhone = (value: string) => {
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(value)) {
      setPhoneError('Formato inválido (+569XXXXXXXX)');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!company.trim()) {
      alert('El Nombre Comercial es obligatorio.');
      return;
    }
    if (seller === '' || sendMethod === '') {
      alert('Por favor, selecciona Vendedor y Medio de Envío.');
      return;
    }
    if (sendMethod === 'whatsapp' && !validatePhone(phone)) return;
    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: existingClientRecord?.id || Date.now().toString(),
      name: name.trim(),
      lastName: lastName.trim(),
      company: company.trim(),
      gender,
      phone: phone.trim(),
      email: email.trim(),
      seller,
      sendMethod,
      deliveryFormat,
      lastSentMethod: sendMethod
    };
    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setLastName(client.lastName || '');
    setCompany(client.company || '');
    setGender(client.gender || '');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || '');
    setDeliveryFormat(client.deliveryFormat || 'link');
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-5">

          <div>
            <label className="block text-xs font-bold text-amber-800 mb-2 uppercase tracking-widest text-center">Configuración de Envío</label>
            <div className="grid grid-cols-2 gap-3">
              <button
                type="button"
                onClick={() => setDeliveryFormat('link')}
                className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 transition-all font-bold text-xs ${
                  deliveryFormat === 'link' 
                    ? 'border-amber-600 bg-amber-50 text-amber-700 shadow-sm' 
                    : 'border-slate-100 bg-slate-50 text-slate-400 hover:bg-slate-100'
                }`}
              >
                <Link className="w-4 h-4" />
                Catálogo Web
              </button>
              <button
                type="button"
                onClick={() => setDeliveryFormat('pdf')}
                className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 transition-all font-bold text-xs ${
                  deliveryFormat === 'pdf' 
                    ? 'border-amber-600 bg-amber-50 text-amber-700 shadow-sm' 
                    : 'border-slate-100 bg-slate-50 text-slate-400 hover:bg-slate-100'
                }`}
              >
                <FileText className="w-4 h-4" />
                Archivo PDF
              </button>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-4 h-4 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all appearance-none font-bold text-sm ${
                    seller === '' ? 'bg-slate-50 border-slate-200 text-slate-400' : 'bg-slate-900 border-slate-800 text-white'
                  }`}
                >
                  <option value="">Seleccionar</option>
                  <option value="OF">OFICINA</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Medio de Envío</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-4 h-4 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => setSendMethod(e.target.value as SendMethod)}
                  className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all appearance-none font-bold text-sm ${
                    sendMethod === '' ? 'bg-slate-50 border-slate-200 text-slate-400' : 'bg-slate-900 border-slate-800 text-white'
                  }`}
                >
                  <option value="">Seleccionar</option>
                  <option value="whatsapp">WhatsApp</option>
                  <option value="email">Email</option>
                </select>
              </div>
            </div>
          </div>

          <h2 className="text-sm font-black text-slate-800 pt-4 flex items-center gap-2 border-t border-slate-100 uppercase tracking-tighter">
            <UserPlus className="w-5 h-5 text-amber-600" />
            Destinatario
          </h2>

          <div className="grid grid-cols-3 gap-3">
            <div>
              <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase truncate">Género</label>
              <div className="relative">
                <select
                  value={gender}
                  onChange={(e) => setGender(e.target.value as GenderType)}
                  className={`w-full px-3 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none appearance-none font-bold text-xs h-[40px] ${
                    gender === '' ? 'bg-slate-50 text-slate-400 border-slate-200' : 'bg-white text-slate-800 border-slate-300'
                  }`}
                >
                  <option value="">Seleccionar</option>
                  <option value="hombre">HOMBRE</option>
                  <option value="mujer">MUJER</option>
                </select>
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase truncate">Nombre</label>
              <div className="relative">
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-800 bg-white font-medium text-xs h-[40px]"
                  placeholder="Ej: Juan"
                />
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-bold text-slate-500 mb-1 uppercase truncate">Apellido</label>
              <div className="relative">
                <input
                  type="text"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-800 bg-white font-medium text-xs h-[40px]"
                  placeholder="Ej: Pérez"
                />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-1">
              {sendMethod === 'email' ? (
                <>
                  <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Email</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
                    <input
                      type="email"
                      value={email}
                      onChange={handleEmailChange}
                      className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-800 bg-white font-bold text-sm ${
                        emailError ? 'border-red-400 bg-red-50' : 'border-slate-300'
                      }`}
                      placeholder="cliente@correo.com"
                      required
                    />
                  </div>
                </>
              ) : (
                <>
                  <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">WhatsApp (+569...)</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
                    <input
                      type="tel"
                      value={phone}
                      onChange={handlePhoneChange}
                      className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-800 bg-white font-bold text-sm ${
                        phoneError ? 'border-red-400 bg-red-50' : 'border-slate-300'
                      }`}
                      placeholder="+56912345678"
                      required
                    />
                  </div>
                </>
              )}
            </div>
            <div className="md:col-span-1">
              <label className="block text-xs font-bold text-slate-500 mb-1 flex justify-between items-center uppercase">
                NOMBRE COMERCIAL (REQUERIDO)
                {existingClientRecord?.lastSentMethod && (
                  <span className="text-[9px] text-green-700 font-black bg-green-100 px-2 py-0.5 rounded flex items-center gap-1 border border-green-200">
                    <CheckCircle2 className="w-2.5 h-2.5" />
                    YA ENVIADO POR: {existingClientRecord.lastSentMethod.toUpperCase()}
                  </span>
                )}
              </label>
              <div className="relative">
                <Briefcase className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
                <input
                  type="text"
                  value={company}
                  onChange={(e) => setCompany(e.target.value)}
                  required
                  className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-800 bg-white font-bold text-sm transition-all uppercase ${
                    existingClientRecord ? 'border-green-400 bg-green-50 shadow-sm' : 'border-slate-300'
                  }`}
                  placeholder="Razón social o nombre de tienda/negocio"
                />
              </div>
            </div>
          </div>

          <div className="pt-2">
            <button
              type="submit"
              className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg active:scale-[0.98]"
            >
              GENERAR MENSAJE PARA ENVÍO
            </button>
          </div>
        </form>
      </div>

      {savedClients.length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <div className="flex items-center justify-between mb-4">
             <h3 className="text-sm font-black text-slate-800 uppercase tracking-tight flex items-center gap-2">
               <History className="w-4 h-4 text-amber-600" />
               Historial Reciente
             </h3>
             <button 
               onClick={onExportClients}
               className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100 flex items-center gap-1.5 hover:bg-indigo-100 transition-all"
             >
               <Download className="w-3 h-3" />
               CSV
             </button>
          </div>
          <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
            {savedClients.map((client) => (
              <div 
                key={client.id}
                onClick={() => loadClient(client)}
                className={`group p-3 rounded-xl border flex items-center justify-between transition-all cursor-pointer ${
                  currentClientId === client.id 
                    ? 'border-amber-400 bg-amber-50 shadow-sm' 
                    : 'border-slate-100 bg-slate-50 hover:border-slate-300 hover:bg-white'
                }`}
              >
                <div className="flex items-center gap-3 overflow-hidden">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 text-xs font-black ${
                    client.sendMethod === 'whatsapp' ? 'bg-green-100 text-green-700' : 'bg-indigo-100 text-indigo-700'
                  }`}>
                    {client.sendMethod === 'whatsapp' ? <Send className="w-4 h-4" /> : <Mail className="w-4 h-4" />}
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-xs font-black text-slate-800 truncate uppercase">{client.company}</p>
                    <p className="text-[10px] text-slate-500 truncate">{client.name} {client.lastName} • {client.seller}</p>
                  </div>
                </div>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    onDeleteClient(client.id);
                  }}
                  className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

