import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserPlus, Briefcase, Phone, Trash2, UserCheck, Mail, Send, Link, FileText, History, Download, CheckCircle2 } from 'lucide-react';
import { ClientData, SellerType, SendMethod, GenderType, DeliveryFormat } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  onExportClients: () => void;
  prefillData?: Partial<ClientData> | null;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  onExportClients,
  prefillData
}) => {
  const [name, setName] = useState('');
  const [lastName, setLastName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('');
  const [sendMethod, setSendMethod] = useState<SendMethod>('');
  const [deliveryFormat, setDeliveryFormat] = useState<DeliveryFormat>('link');

  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const hasAutoSubmitted = useRef(false);

  // Efecto para procesar el autocompletado desde Excel
  useEffect(() => {
    if (prefillData && !hasAutoSubmitted.current) {
      if (prefillData.name) setName(prefillData.name);
      if (prefillData.lastName) setLastName(prefillData.lastName);
      if (prefillData.company) setCompany(prefillData.company);
      if (prefillData.gender) setGender(prefillData.gender);
      if (prefillData.phone) setPhone(prefillData.phone);
      if (prefillData.email) setEmail(prefillData.email);
      if (prefillData.seller) setSeller(prefillData.seller);
      if (prefillData.sendMethod) setSendMethod(prefillData.sendMethod);
      if (prefillData.deliveryFormat) setDeliveryFormat(prefillData.deliveryFormat);

      setPhoneError('');
      setEmailError('');

      // Si tenemos los datos mínimos (Empresa, Vendedor y Método), generamos el mensaje automáticamente
      if (prefillData.company && prefillData.seller && prefillData.sendMethod) {
        const autoClient: ClientData = {
          id: Date.now().toString(),
          name: (prefillData.name || '').trim(),
          lastName: (prefillData.lastName || '').trim(),
          company: prefillData.company.trim(),
          gender: (prefillData.gender as GenderType) || '',
          phone: (prefillData.phone || '').trim(),
          email: (prefillData.email || '').trim(),
          seller: prefillData.seller as SellerType,
          sendMethod: prefillData.sendMethod as SendMethod,
          deliveryFormat: (prefillData.deliveryFormat as DeliveryFormat) || 'link',
        };

        // Pequeño delay para asegurar que el estado se asiente antes de disparar la selección
        setTimeout(() => {
          onClientSelect(autoClient);
          hasAutoSubmitted.current = true;
        }, 100);
      }
    }
  }, [prefillData, onClientSelect]);

  const existingClientRecord = useMemo(() => {
    if (!company.trim() || !seller) return null;
    return savedClients.find(c => 
      c.seller === seller && 
      c.company.toLowerCase().trim() === company.toLowerCase().trim()
    );
  }, [company, seller, savedClients]);

  const validatePhone = (value: string) => {
    // Si viene de Excel, a veces el + se pierde o se codifica mal. Limpiamos.
    const cleanPhone = value.startsWith('+') ? value : `+${value}`;
    const phoneRegex = /^\+569\d{8}$/;
    if (!value) {
      setPhoneError('El teléfono es requerido');
      return false;
    }
    if (!phoneRegex.test(cleanPhone) && value.length > 5) {
      setPhoneError('Formato inválido (+569XXXXXXXX)');
      return false;
    }
    setPhoneError('');
    return true;
  };

  const validateEmail = (value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!value) {
      setEmailError('El email es requerido');
      return false;
    }
    if (!emailRegex.test(value)) {
      setEmailError('Email inválido');
      return false;
    }
    setEmailError('');
    return true;
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.replace(/[^\d+]/g, '');
    setPhone(value);
    if (value.length > 0) validatePhone(value);
    else setPhoneError('');
  };

  const handleEmailChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setEmail(value);
    if (value.length > 0) validateEmail(value);
    else setEmailError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!company.trim()) {
      alert('El Nombre Comercial es obligatorio.');
      return;
    }
    if (seller === '' || sendMethod === '') {
      alert('Por favor, selecciona Vendedor y MEDIO DE ENVÍO.');
      return;
    }

    // Asegurar formato de teléfono para Chile si no lo tiene
    let finalPhone = phone.trim();
    if (sendMethod === 'whatsapp') {
        if (!finalPhone.startsWith('+')) finalPhone = `+${finalPhone}`;
        if (!validatePhone(finalPhone)) return;
    }

    if (sendMethod === 'email' && !validateEmail(email)) return;

    const newClient: ClientData = {
      id: existingClientRecord?.id || Date.now().toString(),
      name: name.trim(),
      lastName: lastName.trim(),
      company: company.trim(),
      gender,
      phone: finalPhone,
      email: email.trim(),
      seller,
      sendMethod,
      deliveryFormat,
      lastSentMethod: sendMethod
    };
    onClientSelect(newClient);
  };

  const loadClient = (client: ClientData) => {
    setName(client.name);
    setLastName(client.lastName || '');
    setCompany(client.company || '');
    setGender(client.gender || '');
    setPhone(client.phone);
    setEmail(client.email || '');
    setSeller(client.seller);
    setSendMethod(client.sendMethod || '');
    setDeliveryFormat(client.deliveryFormat || 'link');
    setPhoneError('');
    setEmailError('');
    onClientSelect(client);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-5">

          <div>
            <label className="block text-xs font-bold text-amber-800 mb-2 uppercase tracking-widest text-center">Configuración de Envío</label>
            <div className="grid grid-cols-2 gap-3">
              <button
                type="button"
                onClick={() => setDeliveryFormat('link')}
                className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 transition-all font-bold text-xs ${
                  deliveryFormat === 'link' 
                    ? 'border-amber-600 bg-amber-50 text-amber-700 shadow-sm' 
                    : 'border-slate-100 bg-slate-50 text-slate-400 hover:bg-slate-100'
                }`}
              >
                <Link className="w-4 h-4" />
                Catálogo Web
              </button>
              <button
                type="button"
                onClick={() => setDeliveryFormat('pdf')}
                className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 transition-all font-bold text-xs ${
                  deliveryFormat === 'pdf' 
                    ? 'border-amber-600 bg-amber-50 text-amber-700 shadow-sm' 
                    : 'border-slate-100 bg-slate-50 text-slate-400 hover:bg-slate-100'
                }`}
              >
                <FileText className="w-4 h-4" />
                Archivo PDF
              </button>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Vendedor</label>
              <div className="relative">
                <UserCheck className="absolute left-3 top-2.5 w-4 h-4 text-slate-400 z-10" />
                <select
                  value={seller}
                  onChange={(e) => setSeller(e.target.value as SellerType)}
                  className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all appearance-none font-bold text-sm ${
                    seller === '' ? 'bg-slate-50 border-slate-200 text-slate-400' : 'bg-slate-900 border-slate-800 text-white'
                  }`}
                >
                  <option value="">Seleccionar</option>
                  <option value="OF">OFICINA</option>
                  <option value="MB">MB</option>
                  <option value="FU">FU</option>
                  <option value="HC">HC</option>
                  <option value="MP">MP</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">MEDIO DE ENVÍO</label>
              <div className="relative">
                <Send className="absolute left-3 top-2.5 w-4 h-4 text-slate-400 z-10" />
                <select
                  value={sendMethod}
                  onChange={(e) => setSendMethod(e.target.value as SendMethod)}
                  className={`w-full pl-10 pr-4 py-2 border rounded-xl focus:ring-2 focus:ring-amber-500 outline-none transition-all appearance-none font-bold text-sm ${
