import React, { useState, useEffect, useCallback } from 'react';
import { Mail, Send, Info } from 'lucide-react';
import { ClientManager } from './components/ClientManager';
import { MessagePreview } from './components/MessagePreview';
import { VideoTutorial } from './components/VideoTutorial';
import { ClientData, SellerType, SendMethod, GenderType, DeliveryFormat } from './types';

function App() {
  const [currentClient, setCurrentClient] = useState<ClientData | null>(null);
  const [savedClients, setSavedClients] = useState<ClientData[]>([]);
  const [urlPrefill, setUrlPrefill] = useState<Partial<ClientData> | null>(null);

  // Captura de datos desde Excel (URL Params)
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const hasAnyParam = params.has('empresa') || params.has('nombre') || params.has('email') || params.has('tel');

    if (hasAnyParam) {
      const prefill: Partial<ClientData> = {
        name: params.get('nombre') || '',
        lastName: params.get('apellido') || '',
        company: params.get('empresa') || '',
        gender: (params.get('genero')?.toLowerCase() as GenderType) || '',
        phone: params.get('tel')?.replace(/\s/g, '+') || '', // Corrige espacios por +
        email: params.get('email') || '',
        seller: (params.get('vendedor')?.toUpperCase() as SellerType) || '',
        sendMethod: (params.get('metodo')?.toLowerCase() as SendMethod) || '',
        deliveryFormat: (params.get('formato') as DeliveryFormat) || 'link',
      };

      setUrlPrefill(prefill);

      // Limpiamos la URL para una experiencia limpia, pero después de capturar
      window.history.replaceState({}, document.title, window.location.pathname);
    }

    const storedClients = localStorage.getItem('infema_v2_clients_vendedores');
    if (storedClients) {
      try { setSavedClients(JSON.parse(storedClients)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('infema_v2_clients_vendedores', JSON.stringify(savedClients));
  }, [savedClients]);

  const handleAddClient = useCallback((client: ClientData) => {
    setSavedClients(prev => {
      const existsIdx = prev.findIndex(c => 
        c.id === client.id || 
        (c.seller === client.seller && c.company.toLowerCase().trim() === client.company.toLowerCase().trim())
      );

      const filteredList = prev.filter((_, idx) => idx !== existsIdx);
      const finalClient: ClientData = {
        ...client,
        id: existsIdx !== -1 ? prev[existsIdx].id : (client.id || Date.now().toString()),
        lastSentMethod: client.sendMethod
      };

      const updatedList = [finalClient, ...filteredList].slice(0, 100);
      setCurrentClient(finalClient);
      return updatedList;
    });
  }, []);

  const handleDeleteClient = useCallback((idToDelete: string) => {
    setSavedClients(prev => prev.filter(c => c.id !== idToDelete));
    setCurrentClient(current => current?.id === idToDelete ? null : current);
  }, []);

  const handleExportClients = useCallback(() => {
    if (savedClients.length === 0) return;
    const headers = ['Nombre Contacto', 'Empresa', 'Género', 'Vendedor', 'Medio', 'Teléfono', 'Email', 'Último Envío'];
    const rows = savedClients.map(client => [
      client.name || '',
      client.company,
      client.gender,
      client.seller,
      client.sendMethod,
      client.phone || '',
      client.email || '',
      client.lastSentMethod || 'Pendiente'
    ]);
    const csvContent = "\uFEFF" + [headers.join(';'), ...rows.map(row => row.join(';'))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `clientes_infema_${new Date().toISOString().slice(0,10)}.csv`;
    link.click();
  }, [savedClients]);

  return (
    <div className="flex flex-col min-h-full bg-slate-50">
      <header className="bg-[#1e293b] text-white shadow-md sticky top-0 z-50 safe-top flex-shrink-0 h-16 flex items-center">
        <div className="max-w-7xl mx-auto px-4 w-full flex items-center justify-between">
          <h1 className="text-xl font-black tracking-tight uppercase italic">INFEMA</h1>
          <div className="text-[10px] font-bold text-amber-400 bg-amber-400/10 px-2 py-0.5 rounded border border-amber-400/20 uppercase tracking-widest">V2.6</div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl w-full mx-auto px-4 py-6 space-y-6">
        <VideoTutorial />

        <section className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
          <div className="bg-slate-800 px-6 py-3 flex items-center gap-2">
            <Info className="w-5 h-5 text-amber-400" />
            <h2 className="text-white font-bold text-sm tracking-wide uppercase">Instrucciones Rápidas</h2>
          </div>
          <div className="p-6 grid md:grid-cols-2 gap-8 text-xs text-slate-600">
             <div className="space-y-3">
                <p className="font-bold text-slate-800 flex items-center gap-2"><Send className="w-4 h-4 text-green-500"/> WHATSAPP:</p>
                <p>1. Clic en <strong>Copiar y abrir</strong>.<br/>2. Pega en el chat. Si es <strong>LINK</strong>, adjunta imagen primero.</p>
             </div>
             <div className="space-y-3">
                <p className="font-bold text-slate-800 flex items-center gap-2"><Mail className="w-4 h-4 text-indigo-500"/> EMAIL:</p>
                <p>1. Clic en <strong>Copiar y abrir</strong>.<br/>2. Simplemente selecciona <strong>Pegar</strong> en el cuerpo del correo.</p>
             </div>
          </div>
        </section>

        <div className="grid lg:grid-cols-2 gap-6">
          <ClientManager 
            onClientSelect={handleAddClient} 
            savedClients={savedClients}
            onDeleteClient={handleDeleteClient}
            currentClientId={currentClient?.id}
            onExportClients={handleExportClients}
            prefillData={urlPrefill}
          />
          <MessagePreview client={currentClient} />
        </div>
      </main>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { UserPlus, Briefcase, Phone, Trash2, UserCheck, Mail, Send, Link, FileText, History, Download, CheckCircle2 } from 'lucide-react';
import { ClientData, SellerType, SendMethod, GenderType, DeliveryFormat } from '../types';

interface ClientManagerProps {
  onClientSelect: (client: ClientData) => void;
  savedClients: ClientData[];
  onDeleteClient: (clientId: string) => void;
  currentClientId?: string;
  onExportClients: () => void;
  prefillData?: Partial<ClientData> | null;
}

export const ClientManager: React.FC<ClientManagerProps> = ({ 
  onClientSelect, 
  savedClients, 
  onDeleteClient,
  currentClientId,
  onExportClients,
  prefillData
}) => {
  const [name, setName] = useState('');
  const [lastName, setLastName] = useState('');
  const [company, setCompany] = useState('');
  const [gender, setGender] = useState<GenderType>('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [seller, setSeller] = useState<SellerType>('');
  const [sendMethod, setSendMethod] = useState<SendMethod>('');
  const [deliveryFormat, setDeliveryFormat] = useState<DeliveryFormat>('link');

  const [phoneError, setPhoneError] = useState('');
  const [emailError, setEmailError] = useState('');

  const hasAutoSubmitted = useRef(false);

  // EFECTO CRÍTICO: Poblar campos desde Excel
  useEffect(() => {
    if (prefillData) {
      // Actualizamos estados aunque sean strings vacíos
      setName(prefillData.name ?? '');
      setLastName(prefillData.lastName ?? '');
      setCompany(prefillData.company ?? '');
      setGender(prefillData.gender ?? '');
      setPhone(prefillData.phone ?? '');
      setEmail(prefillData.email ?? '');
      setSeller(prefillData.seller ?? '');
      setSendMethod(prefillData.sendMethod ?? '');
      setDeliveryFormat(prefillData.deliveryFormat ?? 'link');

      setPhoneError('');
      setEmailError('');

      // Auto-generación si los datos son suficientes
      if (prefillData.company && prefillData.seller && prefillData.sendMethod && !hasAutoSubmitted.current) {
        const autoClient: ClientData = {
          id: Date.now().toString(),
          name: (prefillData.name || '').trim(),
          lastName: (prefillData.lastName || '').trim(),
          company: prefillData.company.trim(),
          gender: (prefillData.gender as GenderType) || '',
          phone: (prefillData.phone || '').trim(),
          email: (prefillData.email || '').trim(),
          seller: prefillData.seller as SellerType,
          sendMethod: prefillData.sendMethod as SendMethod,
          deliveryFormat: (prefillData.deliveryFormat as DeliveryFormat) || 'link',
        };

        setTimeout(() => {
          onClientSelect(autoClient);
          hasAutoSubmitted.current = true;
        }, 300); // Un poco más de tiempo para asegurar que el DOM está listo
      }
    }
  }, [prefillData, onClientSelect]);

  const existingClientRecord = useMemo(() => {
    if (!company.trim() || !seller) return null;
    return savedClients.find(c => 
      c.seller === seller && 
      c.company.toLowerCase().trim() === company.toLowerCase().trim()
    );
  }, [company, seller, savedClients]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!company.trim()) return alert('El Nombre Comercial es obligatorio.');
    if (!seller || !sendMethod) return alert('Selecciona Vendedor y MEDIO.');

    let finalPhone = phone.trim();
    if (sendMethod === 'whatsapp') {
      if (!finalPhone.startsWith('+')) finalPhone = `+${finalPhone}`;
      if (!/^\+569\d{8}$/.test(finalPhone)) {
        setPhoneError('Formato inválido (+569XXXXXXXX)');
        return;
      }
    }

    if (sendMethod === 'email' && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setEmailError('Email inválido');
      return;
    }

    onClientSelect({
      id: existingClientRecord?.id || Date.now().toString(),
      name: name.trim(),
      lastName: lastName.trim(),
      company: company.trim(),
      gender,
      phone: finalPhone,
      email: email.trim(),
      seller,
      sendMethod,
      deliveryFormat,
      lastSentMethod: sendMethod
    });
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="grid grid-cols-2 gap-3">
            <button type="button" onClick={() => setDeliveryFormat('link')} className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 transition-all font-bold text-xs ${deliveryFormat === 'link' ? 'border-amber-600 bg-amber-50 text-amber-700' : 'border-slate-100 bg-slate-50 text-slate-400'}`}><Link className="w-4 h-4" /> Catálogo Web</button>
            <button type="button" onClick={() => setDeliveryFormat('pdf')} className={`flex items-center justify-center gap-2 py-3 px-4 rounded-xl border-2 transition-all font-bold text-xs ${deliveryFormat === 'pdf' ? 'border-amber-600 bg-amber-50 text-amber-700' : 'border-slate-100 bg-slate-50 text-slate-400'}`}><FileText className="w-4 h-4" /> Archivo PDF</button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Vendedor</label>
              <select value={seller} onChange={(e) => setSeller(e.target.value as SellerType)} className="w-full h-10 px-4 border rounded-xl font-bold text-sm bg-slate-900 border-slate-800 text-white outline-none">
                <option value="">Seleccionar</option>
                <option value="OF">OFICINA</option>
                <option value="MB">MB</option>
                <option value="FU">FU</option>
                <option value="HC">HC</option>
                <option value="MP">MP</option>
              </select>
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Medio</label>
              <select value={sendMethod} onChange={(e) => setSendMethod(e.target.value as SendMethod)} className="w-full h-10 px-4 border rounded-xl font-bold text-sm bg-slate-900 border-slate-800 text-white outline-none">
                <option value="">Seleccionar</option>
                <option value="whatsapp">WhatsApp</option>
                <option value="email">Email</option>
              </select>
            </div>
          </div>

          <div className="pt-4 border-t border-slate-100 grid grid-cols-3 gap-3">
             <div className="col-span-1">
               <label className="block text-[10px] font-bold text-slate-500 uppercase">Género</label>
               <select value={gender} onChange={(e) => setGender(e.target.value as GenderType)} className="w-full h-10 px-2 border border-slate-300 rounded-xl text-xs font-bold">
                 <option value="">-</option>
                 <option value="hombre">Sr.</option>
                 <option value="mujer">Sra.</option>
               </select>
             </div>
             <div className="col-span-1">
               <label className="block text-[10px] font-bold text-slate-500 uppercase">Nombre</label>
               <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full h-10 px-3 border border-slate-300 rounded-xl text-xs" />
             </div>
             <div className="col-span-1">
               <label className="block text-[10px] font-bold text-slate-500 uppercase">Apellido</label>
               <input type="text" value={lastName} onChange={(e) => setLastName(e.target.value)} className="w-full h-10 px-3 border border-slate-300 rounded-xl text-xs" />
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-1">
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">{sendMethod === 'email' ? 'Email' : 'WhatsApp'}</label>
              <input 
                type={sendMethod === 'email' ? 'email' : 'tel'} 
                value={sendMethod === 'email' ? email : phone} 
                onChange={(e) => sendMethod === 'email' ? setEmail(e.target.value) : setPhone(e.target.value)} 
                className={`w-full h-10 px-4 border rounded-xl text-sm font-bold ${sendMethod === 'email' ? (emailError ? 'border-red-400' : 'border-slate-300') : (phoneError ? 'border-red-400' : 'border-slate-300')}`}
                placeholder={sendMethod === 'email' ? 'correo@cliente.com' : '+569XXXXXXXX'}
              />
            </div>
            <div className="md:col-span-1">
              <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Empresa / Negocio</label>
              <input type="text" value={company} onChange={(e) => setCompany(e.target.value)} className="w-full h-10 px-4 border border-slate-300 rounded-xl text-sm font-bold uppercase" />
            </div>
          </div>

          <button type="submit" className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-xl shadow-lg transition-transform active:scale-95">GENERAR MENSAJE</button>
        </form>
      </div>

      {savedClients.length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <div className="flex items-center justify-between mb-4">
             <h3 className="text-sm font-black text-slate-800 uppercase flex items-center gap-2"><History className="w-4 h-4 text-amber-600" /> Recientes</h3>
             <button onClick={onExportClients} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100 flex items-center gap-1.5 hover:bg-indigo-100 transition-all"><Download className="w-3 h-3" /> CSV</button>
          </div>
          <div className="space-y-2 max-h-[200px] overflow-y-auto pr-2 custom-scrollbar">
            {savedClients.map((client) => (
              <div key={client.id} onClick={() => onClientSelect(client)} className={`p-3 rounded-xl border flex items-center justify-between cursor-pointer transition-all ${currentClientId === client.id ? 'border-amber-400 bg-amber-50' : 'border-slate-100 bg-slate-50'}`}>
                <div className="overflow-hidden">
                  <p className="text-xs font-black text-slate-800 truncate uppercase">{client.company}</p>
                  <p className="text-[10px] text-slate-500">{client.name} • {client.sendMethod.toUpperCase()}</p>
                </div>
                <button onClick={(e) => { e.stopPropagation(); onDeleteClient(client.id); }} className="p-2 text-slate-300 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

